import { Injectable, signal, computed } from '@angular/core';
import { Observable, Subscription } from 'rxjs';
import { ApiError } from './api.service';

/**
 * Estado de una petición API
 */
export interface ApiState<T> {
  data: T | null;
  loading: boolean;
  error: ApiError | null;
}

/**
 * Resultado del hook useApi
 */
export interface UseApiResult<T> {
  /** Signal con los datos de la respuesta */
  data: () => T | null;
  /** Signal que indica si está cargando */
  loading: () => boolean;
  /** Signal con el error si existe */
  error: () => ApiError | null;
  /** Signal computed que indica si la petición fue exitosa */
  success: () => boolean;
  /** Signal computed que indica si hay error */
  hasError: () => boolean;
  /** Ejecuta una petición */
  execute: (request: Observable<T>) => Subscription;
  /** Resetea el estado */
  reset: () => void;
  /** Actualiza los datos manualmente */
  setData: (data: T) => void;
}

/**
 * Hook signal-based para consumir APIs con estado reactivo.
 * 
 * @example
 * ```typescript
 * // En tu componente
 * private api = inject(ApiService);
 * private userApi = useApi<User[]>();
 * 
 * // Acceso a signals
 * users = this.userApi.data;
 * loading = this.userApi.loading;
 * error = this.userApi.error;
 * 
 * // Ejecutar petición
 * loadUsers() {
 *   this.userApi.execute(this.api.get('/users'));
 * }
 * 
 * // En template
 * @if (loading()) {
 *   <app-loader></app-loader>
 * } @else if (error()) {
 *   <p>Error: {{ error()?.message }}</p>
 * } @else {
 *   @for (user of users(); track user.id) {
 *     <p>{{ user.name }}</p>
 *   }
 * }
 * ```
 */
export function useApi<T>(initialData: T | null = null): UseApiResult<T> {
  const data = signal<T | null>(initialData);
  const loading = signal<boolean>(false);
  const error = signal<ApiError | null>(null);

  const success = computed(() => data() !== null && !loading() && !error());
  const hasError = computed(() => error() !== null);

  let currentSubscription: Subscription | null = null;

  const execute = (request: Observable<T>): Subscription => {
    // Cancel previous request if exists
    if (currentSubscription) {
      currentSubscription.unsubscribe();
    }

    loading.set(true);
    error.set(null);

    currentSubscription = request.subscribe({
      next: (result) => {
        data.set(result);
        loading.set(false);
      },
      error: (err: ApiError) => {
        error.set(err);
        loading.set(false);
      }
    });

    return currentSubscription;
  };

  const reset = (): void => {
    if (currentSubscription) {
      currentSubscription.unsubscribe();
      currentSubscription = null;
    }
    data.set(initialData);
    loading.set(false);
    error.set(null);
  };

  const setData = (newData: T): void => {
    data.set(newData);
    error.set(null);
  };

  return {
    data: data.asReadonly(),
    loading: loading.asReadonly(),
    error: error.asReadonly(),
    success,
    hasError,
    execute,
    reset,
    setData
  };
}

/**
 * Servicio inyectable alternativo para usar con DI.
 * Útil cuando necesitas compartir estado entre componentes.
 * 
 * @example
 * ```typescript
 * // Crear servicio específico
 * @Injectable({ providedIn: 'root' })
 * export class UsersApiService extends UseApiService<User[]> {
 *   private api = inject(ApiService);
 *   
 *   loadUsers() {
 *     this.execute(this.api.get('/users'));
 *   }
 * }
 * ```
 */
@Injectable()
export class UseApiService<T> {
  private readonly _data = signal<T | null>(null);
  private readonly _loading = signal<boolean>(false);
  private readonly _error = signal<ApiError | null>(null);
  private subscription: Subscription | null = null;

  readonly data = this._data.asReadonly();
  readonly loading = this._loading.asReadonly();
  readonly error = this._error.asReadonly();
  readonly success = computed(() => this._data() !== null && !this._loading() && !this._error());
  readonly hasError = computed(() => this._error() !== null);

  execute(request: Observable<T>): Subscription {
    if (this.subscription) {
      this.subscription.unsubscribe();
    }

    this._loading.set(true);
    this._error.set(null);

    this.subscription = request.subscribe({
      next: (result) => {
        this._data.set(result);
        this._loading.set(false);
      },
      error: (err: ApiError) => {
        this._error.set(err);
        this._loading.set(false);
      }
    });

    return this.subscription;
  }

  reset(): void {
    if (this.subscription) {
      this.subscription.unsubscribe();
      this.subscription = null;
    }
    this._data.set(null);
    this._loading.set(false);
    this._error.set(null);
  }

  setData(data: T): void {
    this._data.set(data);
    this._error.set(null);
  }
}

import { Component, Input, ChangeDetectionStrategy } from '@angular/core';

import { AvatarComponent } from '../../atoms/avatar/avatar.component';

export interface AvatarGroupItem {
  name: string;
  initials?: string;
  photo?: string;
  color?: string;
  status?: 'online' | 'offline' | 'away' | 'busy';
  tooltip?: string;
}

/**
 * AvatarGroupComponent — Stack de avatares superpuestos.
 * Muestra los primeros `max` avatares y un contador "+N" si hay más.
 *
 * @example
 * ```html
 * <app-avatar-group [items]="collaborators" [max]="4" size="sm"></app-avatar-group>
 * ```
 */
@Component({
  selector: 'app-avatar-group',
  standalone: true,
  imports: [AvatarComponent],
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <div class="avatar-group" [class]="'avatar-group-' + size">
      @for (item of visible; track item.name; let i = $index) {
        <div
          class="avatar-group-item"
          [style.z-index]="visible.length - i"
          [title]="item.tooltip || item.name"
        >
          <app-avatar
            [initials]="item.initials || getInitials(item.name)"
            [src]="item.photo"
            [status]="item.status"
            [size]="size"
            [color]="item.color"
          ></app-avatar>
        </div>
      }
      @if (overflow > 0) {
        <div class="avatar-group-item avatar-group-overflow" [title]="'+' + overflow + ' más'">
          <div class="overflow-badge" [class]="'overflow-' + size">+{{ overflow }}</div>
        </div>
      }
    </div>
  `,
  styles: [`
    .avatar-group {
      display: flex;
      flex-direction: row;
    }

    .avatar-group-item {
      margin-left: -8px;
      position: relative;
      border-radius: 50%;
      border: 2px solid var(--surface-background, #fff);
      transition: transform 150ms ease, z-index 0ms;
    }

    .avatar-group-sm .avatar-group-item { margin-left: -6px; }
    .avatar-group-lg .avatar-group-item { margin-left: -10px; }
    .avatar-group-xl .avatar-group-item { margin-left: -12px; }

    .avatar-group-item:first-child { margin-left: 0; }

    .avatar-group-item:hover {
      transform: translateY(-2px);
      z-index: 99 !important;
    }

    /* Overflow badge */
    .overflow-badge {
      display: flex;
      align-items: center;
      justify-content: center;
      border-radius: 50%;
      background: var(--color-neutral-200, #e5e7eb);
      color: var(--text-color-secondary, #6b7280);
      font-weight: 600;
      font-size: var(--text-xs, 0.75rem);
      user-select: none;
    }

    .overflow-sm  { width: 28px; height: 28px; font-size: 0.65rem; }
    .overflow-md  { width: 36px; height: 36px; font-size: 0.75rem; }
    .overflow-lg  { width: 48px; height: 48px; font-size: 0.875rem; }
    .overflow-xl  { width: 64px; height: 64px; font-size: 1rem; }
  `]
})
export class AvatarGroupComponent {
  /** Lista completa de avatares */
  @Input() items: AvatarGroupItem[] = [];

  /** Máximo de avatares visibles antes de mostrar contador */
  @Input() max = 5;

  /** Tamaño de los avatares */
  @Input() size: 'sm' | 'md' | 'lg' | 'xl' = 'md';

  get visible(): AvatarGroupItem[] {
    return this.items.slice(0, this.max);
  }

  get overflow(): number {
    return Math.max(0, this.items.length - this.max);
  }

  getInitials(name: string): string {
    return name
      .split(' ')
      .slice(0, 2)
      .map(n => n[0])
      .join('')
      .toUpperCase();
  }
}

