                @if (item.icon) {
                  <i [class]="item.icon" class="breadcrumb-icon" aria-hidden="true"></i>
                }
                {{ item.label }}
              </span>
            }
            @if (!last) {
              <span class="breadcrumb-separator" aria-hidden="true">
                {{ separator }}
              </span>
            }
          </li>
        }
      </ol>
    </nav>
  `,
  styles: [`
    :host { display: block; }

    .breadcrumb-list {
      display: flex;
      flex-wrap: wrap;
      align-items: center;
      list-style: none;
      margin: 0;
      padding: 0;
