import { Component, inject, signal, OnInit, PLATFORM_ID } from '@angular/core';
import { isPlatformBrowser } from '@angular/common';

import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import {
  LayoutShellComponent,
  TopbarComponent,
  SidebarComponent,
  SidebarMenuItem,
  PanelComponent,
  RowComponent,
  AvatarComponent,
  TextComponent,
  ButtonComponent,
  FloatingInputComponent,
  FormRowComponent,
  DividerComponent,
  AlertComponent,
  ChipComponent,
  SkeletonComponent,
  ThemeSwitcherComponent,
  AuthService,
  ApiService,
  useApi,
} from '@shared/ui';

/** Perfil del usuario
 * @customize Ajusta según tu API */
interface UserProfile {
  id:        string;
  firstName: string;
  lastName:  string;
  email:     string;
  role?:     string;
  phone?:    string;
  avatar?:   string;
}

/** Respuesta al guardar perfil */
interface SaveProfileResponse {
  message: string;
}

/** Respuesta al cambiar contraseña */
interface ChangePasswordResponse {
  message: string;
}

const PROFILE_ENDPOINT         = '/Users/GetProfile';
const SAVE_PROFILE_ENDPOINT    = '/Users/UpdateProfile';
const CHANGE_PASSWORD_ENDPOINT = '/Authentication/ChangePassword';

/**
 * Profile Page Blueprint
 *
 * Secciones:
 * - Información personal (nombre, apellido, teléfono)
 * - Cambio de contraseña
 * - Resumen de cuenta (email, rol)
 *
 * @usage
 * 1. Copiar al directorio `pages/` de tu proyecto
 * 2. Ajustar interfaces y endpoints
 * 3. Agregar ruta en app.routes.ts con `canActivate: [authGuard]`
 */
@Component({
  selector: 'app-profile-page',
  standalone: true,
  imports: [
    ReactiveFormsModule,
    LayoutShellComponent,
    TopbarComponent,
    SidebarComponent,
    PanelComponent,
    RowComponent,
    AvatarComponent,
    TextComponent,
    ButtonComponent,
    FloatingInputComponent,
    FormRowComponent,
    DividerComponent,
    AlertComponent,
    ChipComponent,
    SkeletonComponent,
    ThemeSwitcherComponent
],
  templateUrl: './profile-page.component.html',
  styleUrl:    './profile-page.component.css',
})
export class ProfilePageComponent implements OnInit {
  private readonly fb         = inject(FormBuilder);
  private readonly router     = inject(Router);
  private readonly platformId = inject(PLATFORM_ID);
  private readonly api        = inject(ApiService);
  private readonly auth       = inject(AuthService);

  protected sidebarVisible = signal(true);

  protected profileApi     = useApi<UserProfile>();
  protected saveApi        = useApi<SaveProfileResponse>();
  protected passwordApi    = useApi<ChangePasswordResponse>();

  protected saveSuccess    = signal(false);
  protected passSuccess    = signal(false);

  /** Formulario de datos personales */
  protected infoForm = this.fb.group({
    firstName: ['', [Validators.required, Validators.minLength(2)]],
    lastName:  ['', [Validators.required, Validators.minLength(2)]],
    phone:     [''],
  });

  /** Formulario de cambio de contraseña */
  protected passForm = this.fb.group({
    current:  ['', Validators.required],
    password: ['', [Validators.required, Validators.minLength(8)]],
    confirm:  ['', Validators.required],
  }, { validators: this.matchPasswords });

  // ── Sidebar menu ──────────────────────────────────
  protected readonly menuItems: SidebarMenuItem[] = [
    { label: 'Dashboard',  icon: 'fa-solid fa-gauge',      route: '/dashboard' },
    { label: 'Perfil',     icon: 'fa-solid fa-user',       active: true },
    { label: 'Cerrar sesión', icon: 'fa-solid fa-right-from-bracket' },
  ];

  ngOnInit(): void {
    if (isPlatformBrowser(this.platformId)) {
      this.sidebarVisible.set(window.innerWidth >= 768);
    }
    this.loadProfile();
  }

  private loadProfile(): void {
    this.profileApi.execute(
      this.api.get<UserProfile>(PROFILE_ENDPOINT)
    );
    // Cuando lleguen los datos, popular el formulario
    const sub = this.profileApi.data;
    // Effect manual: watch data signal change
    const fill = () => {
      const profile = this.profileApi.data();
      if (profile) {
        this.infoForm.patchValue({
          firstName: profile.firstName,
          lastName:  profile.lastName,
          phone:     profile.phone ?? '',
        });
      }
    };
    // Poll once after execute (signals are synchronous in most cases)
    setTimeout(fill, 100);
    void sub; // suppress unused warning
  }

  protected saveProfile(): void {
    if (this.infoForm.invalid) { this.infoForm.markAllAsTouched(); return; }
    this.saveSuccess.set(false);
    this.saveApi.execute(
      this.api.put<SaveProfileResponse>(SAVE_PROFILE_ENDPOINT, this.infoForm.value)
    );
    // Mostrar éxito
    setTimeout(() => { if (this.saveApi.success()) this.saveSuccess.set(true); }, 300);
  }

  protected changePassword(): void {
    if (this.passForm.invalid) { this.passForm.markAllAsTouched(); return; }
    this.passSuccess.set(false);
    const { current, password } = this.passForm.value;
    this.passwordApi.execute(
      this.api.post<ChangePasswordResponse>(CHANGE_PASSWORD_ENDPOINT, {
        currentPassword: current,
        newPassword: password,
      })
    );
    setTimeout(() => {
      if (this.passwordApi.success()) {
        this.passSuccess.set(true);
        this.passForm.reset();
      }
    }, 300);
  }

  protected logout(): void {
    this.auth.logout();
    this.router.navigate(['/login']);
  }

  protected onToggleSidebar(): void {
    this.sidebarVisible.update(v => !v);
  }

  private matchPasswords(group: import('@angular/forms').AbstractControl) {
    const pw  = group.get('password')?.value;
    const cpw = group.get('confirm')?.value;
    return pw === cpw ? null : { passwordMismatch: true };
  }

  get uf() { return this.infoForm.controls; }
  get pf() { return this.passForm.controls; }
  get currentUser() { return this.auth.currentUser(); }
}

import {
  Component, Input, Output, EventEmitter, signal, computed,
  forwardRef, ChangeDetectionStrategy, ElementRef, ViewChild, inject, PLATFORM_ID
} from '@angular/core';
import { isPlatformBrowser } from '@angular/common';

import { ControlValueAccessor, NG_VALUE_ACCESSOR, FormsModule } from '@angular/forms';

export interface ComboboxOption {
  value: string | number;
  label: string;
  disabled?: boolean;
  group?: string;
}

/**
 * ComboboxComponent — Input con sugerencias de autocompletado.
 *
 * @example
 * ```html
 * <app-combobox
 *   [options]="userOptions"
 *   [(ngModel)]="selectedUser"
 *   label="Buscar usuario"
 *   placeholder="Escribe para buscar..."
 * ></app-combobox>
 * ```
 */
@Component({
  selector: 'app-combobox',
  standalone: true,
  imports: [FormsModule],
  changeDetection: ChangeDetectionStrategy.OnPush,
  providers: [
    {
      provide: NG_VALUE_ACCESSOR,
      useExisting: forwardRef(() => ComboboxComponent),
      multi: true
    }
  ],
  template: `
    <div class="combobox" [class.combobox-open]="isOpen()" [class.combobox-disabled]="disabled">
      @if (label) {
        <label class="combobox-label">{{ label }}</label>
      }
      <div class="combobox-control" #controlRef>
        <input
          #inputRef
          class="combobox-input"
          type="text"
          [placeholder]="placeholder"
          [disabled]="disabled"
          [value]="inputValue()"
          (input)="onInput($event)"
          (focus)="onFocus()"
          (blur)="onBlur()"
          (keydown)="onKeydown($event)"
          autocomplete="off"
          role="combobox"
          [attr.aria-expanded]="isOpen()"
          [attr.aria-autocomplete]="'list'"
          aria-haspopup="listbox"
        />
        @if (inputValue() && !disabled && clearable) {
          <button type="button" class="combobox-clear" (click)="clear()" aria-label="Limpiar">
            <i class="fa-solid fa-xmark"></i>
          </button>
        } @else {
          <span class="combobox-icon"><i class="fa-solid fa-chevron-down"></i></span>
        }
      </div>

      @if (isOpen() && filteredOptions().length > 0) {
        <ul class="combobox-dropdown" role="listbox">
          @for (option of filteredOptions(); track option.value; let i = $index) {
            <li
              class="combobox-option"
              [class.combobox-option-highlighted]="i === highlightedIndex()"
              [class.combobox-option-selected]="option.value === value"
              [class.combobox-option-disabled]="option.disabled"
              role="option"
              [attr.aria-selected]="option.value === value"
              (mousedown)="selectOption(option)"
              (mouseenter)="highlightedIndex.set(i)"
            >
              <span class="combobox-option-label">{{ option.label }}</span>
              @if (option.value === value) {
                <i class="fa-solid fa-check combobox-check" aria-hidden="true"></i>
              }
            </li>
          }
        </ul>
      }

      @if (isOpen() && filteredOptions().length === 0) {
        <div class="combobox-empty">
          <i class="fa-solid fa-magnifying-glass"></i>
          <span>Sin resultados para "{{ inputValue() }}"</span>
        </div>
      }

      @if (error) {
        <span class="combobox-error">{{ error }}</span>
      }
    </div>
  `,
  styles: [`
    .combobox { position: relative; width: 100%; }

    .combobox-label {
      display: block;
      font-size: var(--text-sm);
      font-weight: 500;
      color: var(--text-color-secondary);
      margin-bottom: var(--space-1);
    }

    .combobox-control {
      position: relative;
      display: flex;
      align-items: center;
    }

    .combobox-input {
      width: 100%;
      padding: var(--space-2) var(--space-8) var(--space-2) var(--space-3);
      border: 1px solid var(--border-color);
      border-radius: var(--radius-md);
      background: var(--input-background);
      color: var(--text-color-primary);
      font-size: var(--text-sm);
      line-height: 1.5;
      outline: none;
      transition: border-color 150ms ease, box-shadow 150ms ease;
    }

    .combobox-input:focus {
      border-color: var(--primary-color);
      box-shadow: 0 0 0 3px var(--primary-color-alpha);
    }

    .combobox-input:disabled {
      background: var(--surface-disabled);
      cursor: not-allowed;
      opacity: 0.6;
    }

    .combobox-icon, .combobox-clear {
      position: absolute;
      right: var(--space-3);
      color: var(--text-color-muted);
      font-size: var(--text-sm);
      pointer-events: none;
      background: none;
      border: none;
      cursor: pointer;
      padding: 0;
      display: flex;
      align-items: center;
    }

    .combobox-clear { pointer-events: all; }
    .combobox-clear:hover { color: var(--text-color-primary); }

    .combobox-dropdown {
      position: absolute;
      top: calc(100% + 4px);
      left: 0;
      right: 0;
      z-index: 1000;
      max-height: 240px;
      overflow-y: auto;
      background: var(--surface-background);
      border: 1px solid var(--border-color);
      border-radius: var(--radius-md);
      box-shadow: var(--shadow-lg);
      list-style: none;
      margin: 0;
      padding: var(--space-1) 0;
    }

    .combobox-option {
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: var(--space-2) var(--space-3);
      cursor: pointer;
      font-size: var(--text-sm);
      color: var(--text-color-primary);
      transition: background 100ms ease;
    }

    .combobox-option:hover,
    .combobox-option-highlighted { background: var(--surface-hover); }
    .combobox-option-selected { color: var(--primary-color); font-weight: 500; }
    .combobox-option-disabled { opacity: 0.5; cursor: not-allowed; }

    .combobox-check { color: var(--primary-color); font-size: var(--text-xs); }

    .combobox-empty {
      display: flex;
      align-items: center;
      gap: var(--space-2);
      padding: var(--space-3);
      color: var(--text-color-muted);
      font-size: var(--text-sm);
      position: absolute;
      top: calc(100% + 4px);
      left: 0; right: 0;
      background: var(--surface-background);
      border: 1px solid var(--border-color);
      border-radius: var(--radius-md);
      box-shadow: var(--shadow-lg);
      z-index: 1000;
    }

    .combobox-error {
      display: block;
      font-size: var(--text-xs);
      color: var(--color-error);
      margin-top: var(--space-1);
    }
  `]
})
export class ComboboxComponent implements ControlValueAccessor {
  private readonly platformId = inject(PLATFORM_ID);

  @Input() options: ComboboxOption[] = [];
  @Input() label = '';
  @Input() placeholder = 'Buscar...';
  @Input() disabled = false;
  @Input() clearable = true;
  @Input() error = '';

  @Output() optionSelected = new EventEmitter<ComboboxOption>();
  @Output() inputChange = new EventEmitter<string>();

  @ViewChild('inputRef') inputRef?: ElementRef<HTMLInputElement>;

  value: string | number | null = null;
  inputValue = signal('');
  isOpen = signal(false);
  highlightedIndex = signal(-1);

  filteredOptions = computed(() => {
    const query = this.inputValue().toLowerCase().trim();
    if (!query) return this.options.filter(o => !o.disabled);
    return this.options.filter(o =>
      !o.disabled && o.label.toLowerCase().includes(query)
    );
  });

  private onChange: (v: string | number | null) => void = () => {};
  private onTouched: () => void = () => {};

  writeValue(val: string | number | null): void {
    this.value = val;
    const opt = this.options.find(o => o.value === val);
    this.inputValue.set(opt ? opt.label : '');
  }

  registerOnChange(fn: (v: string | number | null) => void): void { this.onChange = fn; }
  registerOnTouched(fn: () => void): void { this.onTouched = fn; }
  setDisabledState(isDisabled: boolean): void { this.disabled = isDisabled; }

  onInput(event: Event): void {
    const val = (event.target as HTMLInputElement).value;
    this.inputValue.set(val);
    this.isOpen.set(true);
    this.highlightedIndex.set(-1);
    this.inputChange.emit(val);

    if (!val) {
      this.value = null;
      this.onChange(null);
    }
  }

  onFocus(): void { this.isOpen.set(true); }

  onBlur(): void {
    this.onTouched();
    setTimeout(() => this.isOpen.set(false), 150);
  }

  onKeydown(event: KeyboardEvent): void {
    const opts = this.filteredOptions();
    switch (event.key) {
      case 'ArrowDown':
        event.preventDefault();
        this.highlightedIndex.set(Math.min(this.highlightedIndex() + 1, opts.length - 1));
        this.isOpen.set(true);
        break;
      case 'ArrowUp':
        event.preventDefault();
        this.highlightedIndex.set(Math.max(this.highlightedIndex() - 1, 0));
        break;
      case 'Enter':
        event.preventDefault();
        if (this.highlightedIndex() >= 0 && opts[this.highlightedIndex()]) {
          this.selectOption(opts[this.highlightedIndex()]);
        }
        break;
      case 'Escape':
        this.isOpen.set(false);
        break;
    }
  }

  selectOption(option: ComboboxOption): void {
    if (option.disabled) return;
    this.value = option.value;
    this.inputValue.set(option.label);
    this.isOpen.set(false);
    this.highlightedIndex.set(-1);
    this.onChange(option.value);
    this.optionSelected.emit(option);
  }

  clear(): void {
    this.value = null;
    this.inputValue.set('');
    this.isOpen.set(false);
    this.onChange(null);
    if (isPlatformBrowser(this.platformId)) {
      this.inputRef?.nativeElement.focus();
    }
  }
}

import { Component, inject, signal, computed, OnInit, PLATFORM_ID } from '@angular/core';
import { isPlatformBrowser } from '@angular/common';

import { Router } from '@angular/router';
import {
  LayoutShellComponent,
  TopbarComponent,
  SidebarComponent,
  SidebarUser,
  PanelComponent,
  RowComponent,
  AvatarComponent,
  TextComponent,
  ButtonComponent,
