export class FileInputComponent implements ControlValueAccessor {
  private readonly platformId = inject(PLATFORM_ID);

  @ViewChild('fileInput') fileInputRef!: ElementRef<HTMLInputElement>;

  @Input() label = '';
  @Input() hint = '';
  @Input() accept = '';
  @Input() multiple = false;
  @Input() maxSizeMB?: number;
  @Input() disabled = false;
  @Input() error = '';

  @Output() filesChange = new EventEmitter<FileInputFile[]>();

  readonly files = signal<FileInputFile[]>([]);
  readonly isDragging = signal(false);

  private onChange: (v: FileInputFile[]) => void = () => {};
  private onTouched: () => void = () => {};

  onFileChange(event: Event) {
    const input = event.target as HTMLInputElement;
    if (input.files) this.processFiles(Array.from(input.files));
    input.value = '';
  }

  onDragOver(event: DragEvent) {
    event.preventDefault();
    this.isDragging.set(true);
  }

  onDrop(event: DragEvent) {
    event.preventDefault();
    this.isDragging.set(false);
    const dropped = event.dataTransfer?.files;
    if (dropped) this.processFiles(Array.from(dropped));
  }

  private processFiles(rawFiles: File[]) {
    const valid = rawFiles.filter(f => {
      if (this.maxSizeMB && f.size > this.maxSizeMB * 1024 * 1024) return false;
      return true;
    });

    const processed: FileInputFile[] = valid.map(file => ({
      file, name: file.name, size: file.size, type: file.type
    }));

    // Generate image previews (browser only)
    if (isPlatformBrowser(this.platformId)) {
      processed.forEach(pf => {
        if (pf.type.startsWith('image/')) {
          const reader = new FileReader();
          reader.onload = e => {
            pf.preview = e.target?.result as string;
            this.files.update(fs => [...fs]);
          };
          reader.readAsDataURL(pf.file);
        }
      });
    }

    const newFiles = this.multiple ? [...this.files(), ...processed] : processed;
    this.files.set(newFiles);
    this.onChange(newFiles);
    this.filesChange.emit(newFiles);
  }

  removeFile(f: FileInputFile) {
    this.files.update(fs => fs.filter(x => x !== f));
    this.onChange(this.files());
    this.filesChange.emit(this.files());
  }

  formatSize(bytes: number): string {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  }

  // ControlValueAccessor
  writeValue(v: FileInputFile[]): void { this.files.set(v ?? []); }
  registerOnChange(fn: (v: FileInputFile[]) => void): void { this.onChange = fn; }
  registerOnTouched(fn: () => void): void { this.onTouched = fn; }
  setDisabledState(d: boolean): void { this.disabled = d; }
}

import { Component, inject, signal, computed, OnInit } from '@angular/core';

import { FormBuilder, ReactiveFormsModule, FormsModule, Validators } from '@angular/forms';
import {
  PanelComponent,
  ButtonComponent,
  InputComponent,
  Select2Component,
  TableComponent,
  TableHeadComponent,
  TableRowComponent,
  TableCellComponent,
  RowComponent,
  TextComponent,
  ChipComponent,
  IconButtonComponent,
  PaginationComponent,
  ModalComponent,
  FloatingInputComponent,
  LoaderComponent,
  ApiService,
  useApi
} from '@shared/ui';

/**
 * Generic entity interface
 * @customize Adjust to match your data model
 */
export interface Entity {
  id: string | number;
  name: string;
  email: string;
  status: 'active' | 'inactive' | 'pending';
  role: string;
  createdAt: string;
  [key: string]: unknown;
}

/**
 * Paginated response interface
 * @customize Adjust to match your API response
 */
export interface PaginatedResponse<T> {
  data: T[];
  meta: {
    total: number;
    page: number;
    perPage: number;
    totalPages: number;
  };
}

/**
 * Filter options interface
 */
export interface FilterOptions {
  search: string;
  status: string;
  role: string;
}

/**
 * CRUD Table Blueprint
 * 
 * Features:
 * - Data table with pagination
 * - Search and filter functionality
 * - Create/Edit modal
 * - Delete confirmation
 * - Bulk actions
 * - Loading and error states
 * - Responsive design
 * 
 * @usage
 * 1. Copy this folder to your project
 * 2. Rename Entity interface to your model (User, Product, etc.)
 * 3. Configure API endpoints
 * 4. Adjust table columns
 */
@Component({
  selector: 'app-crud-table',
  standalone: true,
  imports: [
    ReactiveFormsModule,
    FormsModule,
    PanelComponent,
    ButtonComponent,
    InputComponent,
    FloatingInputComponent,
    Select2Component,
    PaginationComponent,
    ModalComponent,
    ChipComponent,
    LoaderComponent,
    IconButtonComponent,
    TableComponent,
    TableHeadComponent,
    TableRowComponent,
    TableCellComponent,
    RowComponent,
    TextComponent
],
  templateUrl: './crud-table.component.html',
  styleUrl: './crud-table.component.css'
})
export class CrudTableComponent implements OnInit {
  private fb = inject(FormBuilder);
  private api = inject(ApiService);

  // ============================================
  // CONFIGURATION - Customize these values
  // ============================================

  /** @customize API endpoint for CRUD operations */
  private readonly ENDPOINT = '/users';

  /** @customize Items per page */
  readonly PAGE_SIZE = 10;

  /** @customize Table title */
  readonly TABLE_TITLE = 'Usuarios';

  /** @customize Entity name (singular) */
  readonly ENTITY_NAME = 'Usuario';

  // ============================================
  // STATE
  // ============================================

  private _searchTimeout?: ReturnType<typeof setTimeout>;

  /** List API state */
  listApi = useApi<PaginatedResponse<Entity>>();

  /** Create/Update API state */
  saveApi = useApi<Entity>();

  /** Delete API state */
  deleteApi = useApi<{ success: boolean }>();

  /** Current page */
  currentPage = signal(1);

  /** Search term */
  searchTerm = signal('');

  /** Active filters */
  filters = signal<FilterOptions>({
    search: '',
    status: '',
    role: ''
  });

  /** Selected items for bulk actions */
  selectedItems = signal<Set<string | number>>(new Set());

  /** All items selected flag */
  allSelected = signal(false);

  /** Modal visibility */
  showModal = signal(false);

  /** Delete confirmation modal */
  showDeleteModal = signal(false);

  /** Item to delete */
  itemToDelete = signal<Entity | null>(null);

  /** Edit mode flag */
  isEditMode = signal(false);

  /** Current editing item */
  currentItem = signal<Entity | null>(null);

  // ============================================
  // FILTER OPTIONS
  // ============================================

  /** @customize Status options for filter */
  statusOptions = [
    { value: '', label: 'Todos los estados' },
    { value: 'active', label: 'Activo' },
    { value: 'inactive', label: 'Inactivo' },
    { value: 'pending', label: 'Pendiente' }
  ];

  /** @customize Role options for filter */
  roleOptions = [
    { value: '', label: 'Todos los roles' },
    { value: 'admin', label: 'Administrador' },
    { value: 'user', label: 'Usuario' },
    { value: 'guest', label: 'Invitado' }
  ];

  // ============================================
  // FORM
  // ============================================

  entityForm = this.fb.group({
    name: ['', [Validators.required, Validators.minLength(2)]],
    email: ['', [Validators.required, Validators.email]],
    role: ['user', [Validators.required]],
    status: ['active', [Validators.required]]
  });

  // ============================================
  // COMPUTED
  // ============================================

  /** Current page data */
  items = computed(() => this.listApi.data()?.data ?? []);

  /** Pagination meta */
  meta = computed(() => this.listApi.data()?.meta ?? {
    total: 0,
    page: 1,
    perPage: this.PAGE_SIZE,
    totalPages: 1
  });

  /** Number of selected items */
  selectedCount = computed(() => this.selectedItems().size);

  /** Has selected items */
  hasSelection = computed(() => this.selectedCount() > 0);

  // ============================================
  // LIFECYCLE
  // ============================================

  ngOnInit(): void {
    this.loadData();
  }

  // ============================================
  // DATA LOADING
  // ============================================

  loadData(): void {
    const params: Record<string, string> = {
      page: this.currentPage().toString(),
      perPage: this.PAGE_SIZE.toString()
    };

    const filters = this.filters();
    if (filters.search) params['search'] = filters.search;
    if (filters.status) params['status'] = filters.status;
    if (filters.role) params['role'] = filters.role;

    this.listApi.execute(
      this.api.get<PaginatedResponse<Entity>>(this.ENDPOINT, { params })
    );
  }

  // ============================================
  // PAGINATION
  // ============================================

  onPageChange(page: number): void {
    this.currentPage.set(page);
    this.clearSelection();
    this.loadData();
  }

  // ============================================
  // SEARCH & FILTERS
  // ============================================

  onSearch(event: Event): void {
    const input = event.target as HTMLInputElement;
    this.searchTerm.set(input.value);

    // Debounce search
    clearTimeout(this._searchTimeout);
    this._searchTimeout = setTimeout(() => {
      this.filters.update(f => ({ ...f, search: input.value }));
      this.currentPage.set(1);
      this.loadData();
    }, 300);
  }

  onStatusFilter(status: string): void {
    this.filters.update(f => ({ ...f, status }));
    this.currentPage.set(1);
    this.loadData();
  }

  onRoleFilter(role: string): void {
    this.filters.update(f => ({ ...f, role }));
    this.currentPage.set(1);
    this.loadData();
  }

  clearFilters(): void {
    this.filters.set({ search: '', status: '', role: '' });
    this.searchTerm.set('');
    this.currentPage.set(1);
    this.loadData();
  }

  hasActiveFilters(): boolean {
    const f = this.filters();
    return !!(f.search || f.status || f.role);
  }

  // ============================================
  // SELECTION
  // ============================================

  toggleSelectAll(): void {
    if (this.allSelected()) {
      this.clearSelection();
    } else {
      const allIds = new Set(this.items().map(item => item.id));
      this.selectedItems.set(allIds);
      this.allSelected.set(true);
    }
  }

  toggleSelect(item: Entity): void {
    const selected = new Set(this.selectedItems());
    if (selected.has(item.id)) {
      selected.delete(item.id);
    } else {
      selected.add(item.id);
    }
    this.selectedItems.set(selected);
    this.allSelected.set(selected.size === this.items().length);
  }

  isSelected(item: Entity): boolean {
    return this.selectedItems().has(item.id);
  }

  clearSelection(): void {
    this.selectedItems.set(new Set());
    this.allSelected.set(false);
  }

  // ============================================
  // CREATE / EDIT
  // ============================================

  openCreateModal(): void {
    this.isEditMode.set(false);
    this.currentItem.set(null);
    this.entityForm.reset({
      name: '',
      email: '',
      role: 'user',
      status: 'active'
    });
    this.showModal.set(true);
  }

  openEditModal(item: Entity): void {
    this.isEditMode.set(true);
    this.currentItem.set(item);
    this.entityForm.patchValue({
      name: item.name,
      email: item.email,
      role: item.role,
      status: item.status
    });
    this.showModal.set(true);
  }

  closeModal(): void {
    this.showModal.set(false);
    this.saveApi.reset();
  }

  onSave(): void {
    if (this.entityForm.invalid) {
      this.entityForm.markAllAsTouched();
      return;
    }

    const data = this.entityForm.value;

    if (this.isEditMode()) {
      const item = this.currentItem();
      if (item) {
        this.saveApi.execute(
          this.api.put<Entity>(`${this.ENDPOINT}/${item.id}`, data)
        );
      }
    } else {
      this.saveApi.execute(
        this.api.post<Entity>(this.ENDPOINT, data)
      );
    }

    // Check for success
    const checkSave = setInterval(() => {
      if (this.saveApi.success()) {
        clearInterval(checkSave);
        this.closeModal();
        this.loadData();
      }
    }, 100);
  }

  // ============================================
  // DELETE
  // ============================================

  openDeleteModal(item: Entity): void {
    this.itemToDelete.set(item);
    this.showDeleteModal.set(true);
  }

  closeDeleteModal(): void {
    this.showDeleteModal.set(false);
    this.itemToDelete.set(null);
    this.deleteApi.reset();
  }

  confirmDelete(): void {
    const item = this.itemToDelete();
    if (!item) return;

    this.deleteApi.execute(
      this.api.delete<{ success: boolean }>(`${this.ENDPOINT}/${item.id}`)
    );

    const checkDelete = setInterval(() => {
      if (this.deleteApi.success()) {
        clearInterval(checkDelete);
        this.closeDeleteModal();
        this.loadData();
      }
    }, 100);
  }

  // ============================================
  // BULK ACTIONS
  // ============================================

  bulkDelete(): void {
    const ids = Array.from(this.selectedItems());
    if (ids.length === 0) return;

    // TODO: Implement bulk delete API call
    // Example: this.api.post('/bulk-delete', { ids }).subscribe(() => this.loadData());
    this.clearSelection();
  }

  bulkExport(): void {
    const _ids = Array.from(this.selectedItems());
    // TODO: Implement export functionality
    // Example: this.api.downloadFile('/export', { ids: ids.length > 0 ? ids : 'all' });
  }

  // ============================================
  // HELPERS
  // ============================================

  getStatusVariant(status: string): 'success' | 'warning' | 'error' | 'default' {
    switch (status) {
      case 'active': return 'success';
      case 'pending': return 'warning';
      case 'inactive': return 'error';
      default: return 'default';
    }
  }

  getStatusLabel(status: string): string {
    switch (status) {
      case 'active': return 'Activo';
      case 'pending': return 'Pendiente';
      case 'inactive': return 'Inactivo';
      default: return status;
    }
  }

  formatDate(dateString: string): string {
    return new Date(dateString).toLocaleDateString('es-ES', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  }

  getFieldError(fieldName: string): string {
    const field = this.entityForm.get(fieldName);
    if (!field || !field.touched || !field.errors) return '';

    if (field.errors['required']) return 'Campo requerido';
    if (field.errors['email']) return 'Email inválido';
    if (field.errors['minlength']) {
      return `Mínimo ${field.errors['minlength'].requiredLength} caracteres`;
    }
    return '';
  }
}

import { Component, inject, signal, effect } from '@angular/core';

import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { Observable } from 'rxjs';
import {
  AuthLayoutComponent,
  FloatingInputComponent,
  ButtonComponent,
  CheckboxComponent,
  ApiService,
  useApi,
  FormErrorComponent,
  PanelComponent,
  TextComponent,
  RowComponent,
  FormRowComponent,
  DividerComponent
} from '@shared/ui';

/**
 * Response from login API endpoint
 * @customize Adjust to match your API response structure
 */
interface LoginResponse {
  token: string;
  refreshToken?: string;
  user: {
    id: string;
    name: string;
    email: string;
    role?: string;
  };
}

/**
 * Response from register API endpoint
 * @customize Adjust to match your API response structure
 */
interface RegisterResponse {
  message: string;
  userId?: string;
}

/**
 * Response from forgot password API endpoint
 */
interface ForgotPasswordResponse {
  message: string;
}

/**
 * Login Page Blueprint
 * 
 * Features:
 * - Login form with email/password
 * - Register form with validation
 * - Forgot password flow
 * - Remember me checkbox
 * - API integration with loading states
 * - Error handling and display
 * 
 * @usage
 * 1. Copy this folder to your project's pages directory
 * 2. Update imports to match your project structure
 * 3. Configure API_BASE_URL to your backend
 * 4. Add route in app.routes.ts
 */
@Component({
  selector: 'app-login-page',
  standalone: true,
  imports: [
    ReactiveFormsModule,
    AuthLayoutComponent,
    FloatingInputComponent,
    ButtonComponent,
    CheckboxComponent,
    FormErrorComponent,
    PanelComponent,
    TextComponent,
    RowComponent,
    FormRowComponent,
    DividerComponent
],
  templateUrl: './login-page.component.html',
  styleUrl: './login-page.component.css'
})
export class LoginPageComponent {
  private fb = inject(FormBuilder);
  private api = inject(ApiService);
  private router = inject(Router);

  // ============================================
  // CONFIGURATION - Customize these values
  // ============================================

  /** @customize Set your API base URL */
  private readonly API_BASE_URL = 'https://api.example.com/v1';

  /** @customize Route to redirect after successful login */
  private readonly REDIRECT_AFTER_LOGIN = '/dashboard';

  /** @customize Token storage key */
  private readonly TOKEN_KEY = 'auth_token';

  // ============================================
  // STATE
  // ============================================

  /** Current active view: 'login' | 'register' | 'forgot' */
  activeView = signal<'login' | 'register' | 'forgot'>('login');

  /** API state hooks */
  loginApi = useApi<LoginResponse>();
  registerApi = useApi<RegisterResponse>();
  forgotApi = useApi<ForgotPasswordResponse>();

  /** Success message for forgot password */
  forgotSuccessMessage = signal<string | null>(null);

  // ============================================
  // FORMS
  // ============================================

  loginForm = this.fb.group({
    email: ['', [Validators.required, Validators.email]],
    password: ['', [Validators.required, Validators.minLength(6)]],
    rememberMe: [false]
  });

  registerForm = this.fb.group({
    name: ['', [Validators.required, Validators.minLength(2)]],
    email: ['', [Validators.required, Validators.email]],
    password: ['', [Validators.required, Validators.minLength(8)]],
    confirmPassword: ['', [Validators.required]],
    acceptTerms: [false, [Validators.requiredTrue]]
  });

  forgotForm = this.fb.group({
    email: ['', [Validators.required, Validators.email]]
  });

  // ============================================
  // LIFECYCLE
  // ============================================

  constructor() {
    this.api.setBaseUrl(this.API_BASE_URL);
  }

  // ============================================
  // VIEW SWITCHING
  // ============================================

  showLogin(): void {
    this.activeView.set('login');
    this.resetAllForms();
  }

  showRegister(): void {
    this.activeView.set('register');
    this.resetAllForms();
  }

  showForgot(): void {
    this.activeView.set('forgot');
    this.resetAllForms();
  }

  private resetAllForms(): void {
    this.loginForm.reset();
    this.registerForm.reset();
    this.forgotForm.reset();
    this.loginApi.reset();
    this.registerApi.reset();
    this.forgotApi.reset();
    this.forgotSuccessMessage.set(null);
  }

  // ============================================
  // FORM SUBMISSIONS
  // ============================================

  onLogin(): void {
    if (this.loginForm.invalid) {
      this.loginForm.markAllAsTouched();
      return;
    }

    const { email, rememberMe } = this.loginForm.value;

    // MOCK LOGIN FOR DEMO PURPOSE (Enable real API by uncommenting line below)
    this.loginApi.execute(
      new Observable(observer => {
        setTimeout(() => {
          observer.next({
            token: 'mock-jwt-token-123456',
            user: {
              id: '1',
              name: 'Demo User',
              email: email || 'demo@example.com'
            }
          });
          observer.complete();
        }, 1500);
      })
      // this.api.post<LoginResponse>('/auth/login', { email, password })
    );

    // Handle successful login using effect() for automatic cleanup
    effect(() => {
      if (this.loginApi.success()) {
        const response = this.loginApi.data();
        if (response) {
          this.handleLoginSuccess(response, rememberMe ?? false);
        }
      }
    });
  }

  onRegister(): void {
    if (this.registerForm.invalid) {
      this.registerForm.markAllAsTouched();
      return;
    }

    const { password, confirmPassword } = this.registerForm.value;

    if (password !== confirmPassword) {
      // Handle password mismatch
      return;
    }

    const { name, email } = this.registerForm.value;

    this.registerApi.execute(
      this.api.post<RegisterResponse>('/auth/register', { name, email, password })
    );
  }

  onForgotPassword(): void {
    if (this.forgotForm.invalid) {
      this.forgotForm.markAllAsTouched();
      return;
    }

    const { email } = this.forgotForm.value;

    this.forgotApi.execute(
      this.api.post<ForgotPasswordResponse>('/auth/forgot-password', { email })
    );

    // Handle success using effect() for automatic cleanup
    effect(() => {
      if (this.forgotApi.success()) {
        const response = this.forgotApi.data();
        if (response) {
          this.forgotSuccessMessage.set(response.message || 'Se ha enviado un correo con instrucciones');
        }
      }
    });
  }

  // ============================================
  // HANDLERS
  // ============================================

  private handleLoginSuccess(response: LoginResponse, rememberMe: boolean): void {
    // TODO: SECURITY - Migrar a cookies HttpOnly cuando el backend lo soporte
    // Los tokens en localStorage son vulnerables a ataques XSS
    const storage = rememberMe ? localStorage : sessionStorage;
    storage.setItem(this.TOKEN_KEY, response.token);

    // Set auth header for future requests
    this.api.setAuthToken(response.token);

    // Store user info if needed
    storage.setItem('user', JSON.stringify(response.user));

    // Navigate to dashboard
    this.router.navigate([this.REDIRECT_AFTER_LOGIN]);
  }

  // ============================================
  // FORM FIELD ERRORS
  // ============================================

  getFieldError(form: 'login' | 'register' | 'forgot', fieldName: string): string {
    let field;

    if (form === 'login') {
      field = this.loginForm.get(fieldName);
    } else if (form === 'register') {
      field = this.registerForm.get(fieldName);
    } else {
      field = this.forgotForm.get(fieldName);
    }

    if (!field || !field.touched || !field.errors) {
      return '';
    }

    if (field.errors['required']) {
      return 'Este campo es requerido';
    }
    if (field.errors['email']) {
      return 'Ingresa un email válido';
    }
    if (field.errors['minlength']) {
      const min = field.errors['minlength'].requiredLength;
      return `Mínimo ${min} caracteres`;
    }

    return '';
  }
}

import { Component, inject, signal, effect } from '@angular/core';

import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import {
  AuthLayoutComponent,
  FloatingInputComponent,
  ButtonComponent,
  ApiService,
  useApi,
  PanelComponent,
  TextComponent,
  FormRowComponent,
  AlertComponent,
  DividerComponent,
} from '@shared/ui';

/** Paso actual del flujo de recuperación */
type Step = 'request' | 'sent' | 'reset' | 'done';

/** Respuesta de la API al solicitar reset */
interface ForgotResponse {
  message: string;
}

/** Respuesta de la API al confirmar nueva contraseña */
interface ResetResponse {
  message: string;
}

/**
 * Forgot Password Page Blueprint
 *
 * Flujo de 4 pasos:
 * 1. request — el usuario ingresa su email
 * 2. sent    — confirmación de envío de correo
 * 3. reset   — el usuario ingresa código + nueva contraseña
 * 4. done    — confirmación de restablecimiento
 *
 * @usage
 * 1. Copiar al directorio `pages/` de tu proyecto
 * 2. Configurar `FORGOT_ENDPOINT` y `RESET_ENDPOINT`
 * 3. Agregar ruta en app.routes.ts con `canActivate: [guestGuard]`
 */
const FORGOT_ENDPOINT = '/Authentication/ForgotPassword';
const RESET_ENDPOINT  = '/Authentication/ResetPassword';

@Component({
  selector: 'app-forgot-password-page',
  standalone: true,
  imports: [
    ReactiveFormsModule,
    AuthLayoutComponent,
    FloatingInputComponent,
    ButtonComponent,
    PanelComponent,
    TextComponent,
    FormRowComponent,
    AlertComponent,
    DividerComponent
],
  templateUrl: './forgot-password-page.component.html',
  styleUrl:    './forgot-password-page.component.css',
})
export class ForgotPasswordPageComponent {
  private readonly fb     = inject(FormBuilder);
  private readonly router = inject(Router);
  private readonly api    = inject(ApiService);

  protected step = signal<Step>('request');

  protected forgotApi = useApi<ForgotResponse>();
  protected resetApi  = useApi<ResetResponse>();

  /** Formulario paso 1: email */
  protected emailForm = this.fb.group({
    email: ['', [Validators.required, Validators.email]],
  });

  /** Formulario paso 3: código + nueva contraseña */
  protected resetForm = this.fb.group({
    code:     ['', Validators.required],
    password: ['', [Validators.required, Validators.minLength(8)]],
    confirm:  ['', Validators.required],
  }, { validators: this.matchPasswords });

  constructor() {
    effect(() => {
      if (this.forgotApi.success()) this.step.set('sent');
    });
    effect(() => {
      if (this.resetApi.success()) this.step.set('done');
    });
  }

  private matchPasswords(group: import('@angular/forms').AbstractControl) {
    const pw  = group.get('password')?.value;
    const cpw = group.get('confirm')?.value;
    return pw === cpw ? null : { passwordMismatch: true };
  }

  protected submitEmail(): void {
    if (this.emailForm.invalid) { this.emailForm.markAllAsTouched(); return; }
    this.forgotApi.execute(
      this.api.post<ForgotResponse>(FORGOT_ENDPOINT, { email: this.emailForm.value.email })
    );
  }

  protected submitReset(): void {
    if (this.resetForm.invalid) { this.resetForm.markAllAsTouched(); return; }
    const { code, password } = this.resetForm.value;
    this.resetApi.execute(
      this.api.post<ResetResponse>(RESET_ENDPOINT, {
        email: this.emailForm.value.email,
        token: code,
        newPassword: password,
      })
    );
  }

  protected goToLogin(): void {
    this.router.navigate(['/login']);
  }

  protected resend(): void {
    this.forgotApi.reset();
    this.submitEmail();
  }

  get ef() { return this.emailForm.controls; }
  get rf() { return this.resetForm.controls; }
}

import { Injectable, signal, computed, PLATFORM_ID, inject } from '@angular/core';
import { isPlatformBrowser } from '@angular/common';

/**
 * Token configuration for multi-app environments
 */
export interface TokenConfig {
    /** Application ID for token isolation */
    appId: string;
    /** Token expiry buffer in milliseconds (default: 5 minutes) */
    expiryBuffer?: number;
    /** Use secure cookies (HTTPS only) */
    secure?: boolean;
}

/**
 * Decoded JWT payload structure
 */
export interface JwtPayload {
    exp?: number;
    iat?: number;
    sub?: string;
    [key: string]: unknown;
}

/**
 * TokenService - Secure token management with cookies
 * 
 * Features:
 * - Cookie-based token storage (more secure than localStorage for XSS)
 * - Multi-app support with isolated tokens
 * - Automatic token expiry detection
 * - SSR-safe implementation
 * 
 * @usage
 * ```typescript
 * // Inject service
 * private tokenService = inject(TokenService);
 * 
 * // Save token for app
 * tokenService.saveTokenApp('jwt-token', '2');
 * 
 * // Get token
 * const token = tokenService.getTokenApp('2');
 * 
 * // Check if valid
 * if (tokenService.hasValidToken('2')) { ... }
 * 
 * // Clear on logout
 * tokenService.removeTokenApp('2');
 * ```
 */
@Injectable({
    providedIn: 'root'
})
export class TokenService {
    private platformId = inject(PLATFORM_ID);

    // ============================================
    // CONFIGURATION
    // ============================================

    /** Default expiry buffer: 5 minutes before actual expiry */
    private readonly DEFAULT_EXPIRY_BUFFER = 5 * 60 * 1000;

    /** Cookie path */
    private readonly COOKIE_PATH = '/';

    /** Token cookie prefix */
    private readonly TOKEN_PREFIX = 'app_token_';

    /** Refresh token cookie prefix */
    private readonly REFRESH_PREFIX = 'app_refresh_';

    // ============================================
    // STATE
    // ============================================

    /** Current app ID being used */
    private currentAppId = signal<string | null>(null);

    /** Whether browser environment is available */
    private readonly isBrowser = computed(() => isPlatformBrowser(this.platformId));

    // ============================================
    // PUBLIC API - Token Operations
    // ============================================

    /**
     * Save access token for a specific application
     * @param token JWT access token
     * @param appId Application identifier
     * @param expiresInSeconds Optional expiry in seconds (defaults to token's exp claim)
     */
    saveTokenApp(token: string, appId: string, expiresInSeconds?: number): void {
        if (!this.isBrowser()) return;

        const cookieName = this.getTokenCookieName(appId);
        let expiry: Date | undefined;

        if (expiresInSeconds) {
            expiry = new Date(Date.now() + expiresInSeconds * 1000);
        } else {
            // Try to extract expiry from JWT
            const payload = this.decodeToken(token);
            if (payload?.exp) {
                expiry = new Date(payload.exp * 1000);
            }
        }

        this.setCookie(cookieName, token, expiry);
        this.currentAppId.set(appId);
    }

    /**
     * Save refresh token for a specific application
     * @param token Refresh token
     * @param appId Application identifier
     * @param expiresInDays Optional expiry in days (default: 30)
     */
    saveRefreshToken(token: string, appId: string, expiresInDays = 30): void {
        if (!this.isBrowser()) return;

        const cookieName = this.getRefreshCookieName(appId);
        const expiry = new Date(Date.now() + expiresInDays * 24 * 60 * 60 * 1000);

        this.setCookie(cookieName, token, expiry);
    }

    /**
     * Get access token for a specific application
     * @param appId Application identifier
     * @returns Token string or null if not found
     */
    getTokenApp(appId: string): string | null {
        if (!this.isBrowser()) return null;

        const cookieName = this.getTokenCookieName(appId);
        return this.getCookie(cookieName);
    }

    /**
     * Get refresh token for a specific application
     * @param appId Application identifier
     * @returns Refresh token string or null
     */
    getRefreshToken(appId: string): string | null {
        if (!this.isBrowser()) return null;

        const cookieName = this.getRefreshCookieName(appId);
        return this.getCookie(cookieName);
    }

    /**
     * Remove all tokens for a specific application (logout)
     * @param appId Application identifier
     */
    removeTokenApp(appId: string): void {
        if (!this.isBrowser()) return;

        this.deleteCookie(this.getTokenCookieName(appId));
        this.deleteCookie(this.getRefreshCookieName(appId));

        if (this.currentAppId() === appId) {
            this.currentAppId.set(null);
        }
    }

    /**
     * Check if a valid (non-expired) token exists for an app
     * @param appId Application identifier
     * @returns true if valid token exists
     */
    hasValidToken(appId: string): boolean {
        const token = this.getTokenApp(appId);
        if (!token) return false;

        return !this.isTokenExpired(token);
    }

    /**
     * Check if token is expired or about to expire
     * @param token JWT token string
     * @param bufferMs Buffer before expiry (default: 5 minutes)
     * @returns true if expired or expiring soon
     */
    isTokenExpired(token: string, bufferMs = this.DEFAULT_EXPIRY_BUFFER): boolean {
        const payload = this.decodeToken(token);
        if (!payload?.exp) return false; // Can't determine, assume valid

        const expiryTime = payload.exp * 1000;
        const now = Date.now();

        return now >= (expiryTime - bufferMs);
    }

    /**
     * Decode JWT token payload (without verification)
     * @param token JWT token string
     * @returns Decoded payload or null
     */
    decodeToken(token: string): JwtPayload | null {
        try {
            const parts = token.split('.');
            if (parts.length !== 3) return null;

            const payload = parts[1];
            const decoded = atob(payload.replace(/-/g, '+').replace(/_/g, '/'));
            return JSON.parse(decoded);
        } catch {
            return null;
        }
    }

    /**
     * Get user ID from token
     * @param appId Application identifier
     * @returns User ID or null
     */
    getUserId(appId: string): string | null {
        const token = this.getTokenApp(appId);
        if (!token) return null;

        const payload = this.decodeToken(token);
        return payload?.sub ?? null;
    }

    // ============================================
    // LEGACY API (for backward compatibility)
    // ============================================

    /**
     * @deprecated Use saveTokenApp instead
     */
    saveToken(value: string): void {
        this.setCookie('value-token', value);
    }

    /**
     * @deprecated Use getTokenApp instead
     */
    getToken(): string | null {
        return this.getCookie('value-token');
    }

    // ============================================
    // PRIVATE - Cookie Operations
    // ============================================

    private getTokenCookieName(appId: string): string {
        return `${this.TOKEN_PREFIX}${appId}`;
    }

    private getRefreshCookieName(appId: string): string {
        return `${this.REFRESH_PREFIX}${appId}`;
    }

    private setCookie(name: string, value: string, expires?: Date, secure = false): void {
        if (!this.isBrowser()) return;

        let cookie = `${encodeURIComponent(name)}=${encodeURIComponent(value)}`;
        cookie += `; path=${this.COOKIE_PATH}`;

        if (expires) {
            cookie += `; expires=${expires.toUTCString()}`;
        }

        if (secure || location.protocol === 'https:') {
            cookie += '; secure';
        }

        // SameSite for CSRF protection
        cookie += '; SameSite=Strict';

        document.cookie = cookie;
    }

    private getCookie(name: string): string | null {
        if (!this.isBrowser()) return null;

        const nameEQ = encodeURIComponent(name) + '=';
        const cookies = document.cookie.split(';');

        for (const cookie of cookies) {
            const c = cookie.trim();
            if (c.indexOf(nameEQ) === 0) {
                return decodeURIComponent(c.substring(nameEQ.length));
            }
        }

        return null;
    }

    private deleteCookie(name: string): void {
        if (!this.isBrowser()) return;

        document.cookie = `${encodeURIComponent(name)}=; path=${this.COOKIE_PATH}; expires=Thu, 01 Jan 1970 00:00:00 GMT`;
    }
}

