import { Injectable, inject, signal, computed } from '@angular/core';
import { Router } from '@angular/router';
import { Observable, of, throwError } from 'rxjs';
import { tap, catchError, switchMap } from 'rxjs/operators';

import { ApiService } from './api.service';
import { TokenService } from './token.service';

/**
 * User profile structure
 * @customize Adjust to match your API response
 */
export interface UserProfile {
    id: string | number;
    user: string;
    names: string;
    email?: string;
    role?: string;
    [key: string]: unknown;
}

/**
 * Login request structure
 * @customize Adjust to match your API
 */
export interface LoginRequest {
    v_user: string;
    v_password: string;
    v_ip?: string;
}

/**
 * Login response structure
 * @customize Adjust to match your API response
 */
export interface LoginResponse {
    access_Token: string;
    refresh_Token?: string;
    b_CAMBIO_CONTRASENIA?: boolean;
    user?: UserProfile;
}

/**
 * Refresh token request
 */
export interface RefreshTokenRequest {
    v_ACCESS_TOKEN: string;
    v_REFRESH_TOKEN: string;
}

/**
 * AuthService - Authentication management
 * 
 * Features:
 * - Login with username/password
 * - Automatic token refresh
 * - User profile management
 * - Logout and session cleanup
 * - Multi-app authentication support
 * 
 * @usage
 * ```typescript
 * // In component
 * private auth = inject(AuthService);
 * 
 * // Login
 * auth.login({ v_user: 'admin', v_password: '123' }).subscribe();
 * 
 * // Check auth state
 * if (auth.isAuthenticated()) { ... }
 * 
 * // Get current user
 * const user = auth.currentUser();
 * 
 * // Logout
 * auth.logout();
 * ```
 */
@Injectable({
    providedIn: 'root'
})
export class AuthService {
    private api = inject(ApiService);
    private tokenService = inject(TokenService);
    private router = inject(Router);

    // ============================================
    // CONFIGURATION - Customize these values
    // ============================================

    /** @customize Application ID for token storage */
    private appId = '2';

    /** @customize API endpoints */
    private readonly ENDPOINTS = {
        login: '/Authentication/PostLogin',
        profile: '/Authentication/Get_user_profile',
        refresh: '/Authentication/Post_refresh_token',
        changePassword: '/Authentication/Post_change_password'
    };

    /** @customize Route after logout */
    private readonly LOGIN_ROUTE = '/login';

    // ============================================
    // STATE
    // ============================================

    /** Current authenticated user */
    private _currentUser = signal<UserProfile | null>(null);

    /** Loading state */
    private _loading = signal(false);

    /** Error state */
    private _error = signal<string | null>(null);

    /** Password change required flag */
    private _requiresPasswordChange = signal(false);

    // ============================================
    // COMPUTED
    // ============================================

    /** Current user (readonly) */
    readonly currentUser = this._currentUser.asReadonly();

    /** Authentication status */
    readonly isAuthenticated = computed(() =>
        this.tokenService.hasValidToken(this.appId) && this._currentUser() !== null
    );

    /** Loading state */
    readonly loading = this._loading.asReadonly();

    /** Error message */
    readonly error = this._error.asReadonly();

    /** Password change required */
    readonly requiresPasswordChange = this._requiresPasswordChange.asReadonly();

    // ============================================
    // PUBLIC API
    // ============================================

    /**
     * Configure the app ID for multi-app environments
     * @param appId Application identifier
     */
    configure(appId: string): void {
        this.appId = appId;
        // Check if already authenticated
        if (this.tokenService.hasValidToken(appId)) {
            this.loadUserProfile().subscribe();
        }
    }

    /**
     * Login with credentials
     * @param credentials Login credentials
     * @returns Observable of login response
     */
    login(credentials: LoginRequest): Observable<LoginResponse> {
        this._loading.set(true);
        this._error.set(null);

        return this.api.post<LoginResponse>(this.ENDPOINTS.login, credentials).pipe(
            tap(response => {
                // Save tokens
                this.tokenService.saveTokenApp(response.access_Token, this.appId);

                if (response.refresh_Token) {
                    this.tokenService.saveRefreshToken(response.refresh_Token, this.appId);
                }

                // Check for password change requirement
                this._requiresPasswordChange.set(response.b_CAMBIO_CONTRASENIA ?? false);

                // Set user if included in response
                if (response.user) {
                    this._currentUser.set(response.user);
                }

                // Set auth header for future requests
                this.api.setAuthToken(response.access_Token);
            }),
            switchMap(response => {
                // Load full profile if not included
                if (!response.user) {
                    return this.loadUserProfile().pipe(
                        switchMap(() => of(response))
                    );
                }
                return of(response);
            }),
            tap(() => this._loading.set(false)),
            catchError(error => {
                this._loading.set(false);
                this._error.set(error.message || 'Error de autenticación');
                return throwError(() => error);
            })
        );
    }

    /**
     * Load user profile from API
     * @returns Observable of user profile
     */
    loadUserProfile(): Observable<UserProfile> {
        const userId = this.tokenService.getUserId(this.appId);

        return this.api.get<{ value: UserProfile }>(
            `${this.ENDPOINTS.profile}?I_ID_USER=${userId}`
        ).pipe(
            tap(response => {
                this._currentUser.set(response.value);
            }),
            switchMap(response => of(response.value))
        );
    }

    /**
     * Refresh access token using refresh token
     * @returns Observable of new login response
     */
    refreshToken(): Observable<LoginResponse> {
        const accessToken = this.tokenService.getTokenApp(this.appId);
        const refreshToken = this.tokenService.getRefreshToken(this.appId);

        if (!accessToken || !refreshToken) {
            return throwError(() => new Error('No tokens available'));
        }

        const request: RefreshTokenRequest = {
            v_ACCESS_TOKEN: accessToken,
            v_REFRESH_TOKEN: refreshToken
        };

        return this.api.post<LoginResponse>(this.ENDPOINTS.refresh, request).pipe(
            tap(response => {
                this.tokenService.saveTokenApp(response.access_Token, this.appId);

                if (response.refresh_Token) {
                    this.tokenService.saveRefreshToken(response.refresh_Token, this.appId);
                }

                this.api.setAuthToken(response.access_Token);
            }),
            catchError(error => {
                // If refresh fails, force logout
                this.logout();
                return throwError(() => error);
            })
        );
    }

    /**
     * Logout and clear all session data
     * @param redirect Whether to redirect to login page (default: true)
     */
    logout(redirect = true): void {
        this.tokenService.removeTokenApp(this.appId);
        this._currentUser.set(null);
        this._error.set(null);
        this.api.setAuthToken('');

        if (redirect) {
            this.router.navigate([this.LOGIN_ROUTE]);
        }
    }

    /**
     * Check if current token is about to expire
     * @returns true if token expires within 5 minutes
     */
    isTokenExpiring(): boolean {
        const token = this.tokenService.getTokenApp(this.appId);
        if (!token) return true;

        return this.tokenService.isTokenExpired(token, 5 * 60 * 1000);
    }

    /**
     * Get current access token
     * @returns Current token or null
     */
    getToken(): string | null {
        return this.tokenService.getTokenApp(this.appId);
    }

    /**
     * Clear error state
     */
    clearError(): void {
        this._error.set(null);
    }
}

import { Component, inject, signal, effect } from '@angular/core';

import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { Observable } from 'rxjs';
import {
  AuthLayoutComponent,
  FloatingInputComponent,
  ButtonComponent,
  CheckboxComponent,
  ApiService,
  useApi,
  FormErrorComponent,
  PanelComponent,
  TextComponent,
  RowComponent,
  FormRowComponent,
  DividerComponent
} from '@shared/ui';

/**
 * Response from login API endpoint
 * @customize Adjust to match your API response structure
 */
interface LoginResponse {
  token: string;
  refreshToken?: string;
  user: {
    id: string;
    name: string;
    email: string;
    role?: string;
  };
}

/**
 * Response from register API endpoint
 * @customize Adjust to match your API response structure
 */
interface RegisterResponse {
  message: string;
  userId?: string;
}

/**
 * Response from forgot password API endpoint
 */
interface ForgotPasswordResponse {
  message: string;
}

/**
 * Login Page Blueprint
 * 
 * Features:
 * - Login form with email/password
 * - Register form with validation
 * - Forgot password flow
 * - Remember me checkbox
 * - API integration with loading states
 * - Error handling and display
 * 
 * @usage
 * 1. Copy this folder to your project's pages directory
 * 2. Update imports to match your project structure
 * 3. Configure API_BASE_URL to your backend
 * 4. Add route in app.routes.ts
 */
@Component({
  selector: 'app-login-page',
  standalone: true,
  imports: [
    ReactiveFormsModule,
    AuthLayoutComponent,
    FloatingInputComponent,
    ButtonComponent,
    CheckboxComponent,
    FormErrorComponent,
    PanelComponent,
    TextComponent,
    RowComponent,
    FormRowComponent,
    DividerComponent
],
  templateUrl: './login-page.component.html',
  styleUrl: './login-page.component.css'
})
export class LoginPageComponent {
  private fb = inject(FormBuilder);
  private api = inject(ApiService);
  private router = inject(Router);

  // ============================================
  // CONFIGURATION - Customize these values
  // ============================================

  /** @customize Set your API base URL */
  private readonly API_BASE_URL = 'https://api.example.com/v1';

  /** @customize Route to redirect after successful login */
  private readonly REDIRECT_AFTER_LOGIN = '/dashboard';

  /** @customize Token storage key */
  private readonly TOKEN_KEY = 'auth_token';

  // ============================================
  // STATE
  // ============================================

  /** Current active view: 'login' | 'register' | 'forgot' */
  activeView = signal<'login' | 'register' | 'forgot'>('login');

  /** API state hooks */
  loginApi = useApi<LoginResponse>();
  registerApi = useApi<RegisterResponse>();
  forgotApi = useApi<ForgotPasswordResponse>();

  /** Success message for forgot password */
  forgotSuccessMessage = signal<string | null>(null);

  // ============================================
  // FORMS
  // ============================================

  loginForm = this.fb.group({
    email: ['', [Validators.required, Validators.email]],
    password: ['', [Validators.required, Validators.minLength(6)]],
    rememberMe: [false]
  });

  registerForm = this.fb.group({
    name: ['', [Validators.required, Validators.minLength(2)]],
    email: ['', [Validators.required, Validators.email]],
    password: ['', [Validators.required, Validators.minLength(8)]],
    confirmPassword: ['', [Validators.required]],
    acceptTerms: [false, [Validators.requiredTrue]]
  });

  forgotForm = this.fb.group({
    email: ['', [Validators.required, Validators.email]]
  });

  // ============================================
  // LIFECYCLE
  // ============================================

  constructor() {
    this.api.setBaseUrl(this.API_BASE_URL);
  }

  // ============================================
  // VIEW SWITCHING
  // ============================================

  showLogin(): void {
    this.activeView.set('login');
    this.resetAllForms();
  }

  showRegister(): void {
    this.activeView.set('register');
    this.resetAllForms();
  }

  showForgot(): void {
    this.activeView.set('forgot');
    this.resetAllForms();
  }

  private resetAllForms(): void {
    this.loginForm.reset();
    this.registerForm.reset();
    this.forgotForm.reset();
    this.loginApi.reset();
    this.registerApi.reset();
    this.forgotApi.reset();
    this.forgotSuccessMessage.set(null);
  }

  // ============================================
  // FORM SUBMISSIONS
  // ============================================

  onLogin(): void {
    if (this.loginForm.invalid) {
      this.loginForm.markAllAsTouched();
      return;
    }

    const { email, rememberMe } = this.loginForm.value;

    // MOCK LOGIN FOR DEMO PURPOSE (Enable real API by uncommenting line below)
    this.loginApi.execute(
      new Observable(observer => {
        setTimeout(() => {
          observer.next({
            token: 'mock-jwt-token-123456',
            user: {
              id: '1',
              name: 'Demo User',
              email: email || 'demo@example.com'
            }
          });
          observer.complete();
        }, 1500);
      })
      // this.api.post<LoginResponse>('/auth/login', { email, password })
    );

    // Handle successful login using effect() for automatic cleanup
    effect(() => {
      if (this.loginApi.success()) {
        const response = this.loginApi.data();
        if (response) {
          this.handleLoginSuccess(response, rememberMe ?? false);
        }
      }
    });
  }

  onRegister(): void {
    if (this.registerForm.invalid) {
      this.registerForm.markAllAsTouched();
      return;
    }

    const { password, confirmPassword } = this.registerForm.value;

    if (password !== confirmPassword) {
      // Handle password mismatch
      return;
    }

    const { name, email } = this.registerForm.value;

    this.registerApi.execute(
      this.api.post<RegisterResponse>('/auth/register', { name, email, password })
    );
  }

  onForgotPassword(): void {
    if (this.forgotForm.invalid) {
      this.forgotForm.markAllAsTouched();
      return;
    }

    const { email } = this.forgotForm.value;

    this.forgotApi.execute(
      this.api.post<ForgotPasswordResponse>('/auth/forgot-password', { email })
    );

    // Handle success using effect() for automatic cleanup
    effect(() => {
      if (this.forgotApi.success()) {
        const response = this.forgotApi.data();
        if (response) {
          this.forgotSuccessMessage.set(response.message || 'Se ha enviado un correo con instrucciones');
        }
      }
    });
  }

  // ============================================
  // HANDLERS
  // ============================================

  private handleLoginSuccess(response: LoginResponse, rememberMe: boolean): void {
    // TODO: SECURITY - Migrar a cookies HttpOnly cuando el backend lo soporte
    // Los tokens en localStorage son vulnerables a ataques XSS
    const storage = rememberMe ? localStorage : sessionStorage;
    storage.setItem(this.TOKEN_KEY, response.token);

    // Set auth header for future requests
    this.api.setAuthToken(response.token);

    // Store user info if needed
    storage.setItem('user', JSON.stringify(response.user));

    // Navigate to dashboard
    this.router.navigate([this.REDIRECT_AFTER_LOGIN]);
  }

  // ============================================
  // FORM FIELD ERRORS
  // ============================================

  getFieldError(form: 'login' | 'register' | 'forgot', fieldName: string): string {
    let field;

    if (form === 'login') {
      field = this.loginForm.get(fieldName);
    } else if (form === 'register') {
      field = this.registerForm.get(fieldName);
    } else {
      field = this.forgotForm.get(fieldName);
    }

    if (!field || !field.touched || !field.errors) {
      return '';
    }

    if (field.errors['required']) {
      return 'Este campo es requerido';
    }
    if (field.errors['email']) {
      return 'Ingresa un email válido';
    }
    if (field.errors['minlength']) {
      const min = field.errors['minlength'].requiredLength;
      return `Mínimo ${min} caracteres`;
    }

    return '';
  }
}

import { Injectable, inject, signal, computed } from '@angular/core';
import { Router } from '@angular/router';
import { Observable, of, throwError } from 'rxjs';
import { tap, catchError, switchMap } from 'rxjs/operators';

import { ApiService } from './api.service';
import { TokenService } from './token.service';

/**
 * User profile structure
 * @customize Adjust to match your API response
 */
export interface UserProfile {
    id: string | number;
    user: string;
    names: string;
    email?: string;
    role?: string;
    [key: string]: unknown;
}

/**
 * Login request structure
 * @customize Adjust to match your API
 */
export interface LoginRequest {
    v_user: string;
    v_password: string;
    v_ip?: string;
}

/**
 * Login response structure
 * @customize Adjust to match your API response
 */
export interface LoginResponse {
    access_Token: string;
    refresh_Token?: string;
    b_CAMBIO_CONTRASENIA?: boolean;
    user?: UserProfile;
}

/**
 * Refresh token request
 */
export interface RefreshTokenRequest {
    v_ACCESS_TOKEN: string;
    v_REFRESH_TOKEN: string;
}

/**
 * AuthService - Authentication management
 * 
 * Features:
 * - Login with username/password
 * - Automatic token refresh
 * - User profile management
 * - Logout and session cleanup
 * - Multi-app authentication support
 * 
 * @usage
 * ```typescript
 * // In component
 * private auth = inject(AuthService);
 * 
 * // Login
 * auth.login({ v_user: 'admin', v_password: '123' }).subscribe();
 * 
 * // Check auth state
 * if (auth.isAuthenticated()) { ... }
 * 
 * // Get current user
 * const user = auth.currentUser();
 * 
 * // Logout
 * auth.logout();
 * ```
 */
@Injectable({
    providedIn: 'root'
})
export class AuthService {
    private api = inject(ApiService);
    private tokenService = inject(TokenService);
    private router = inject(Router);

    // ============================================
    // CONFIGURATION - Customize these values
    // ============================================

    /** @customize Application ID for token storage */
    private appId = '2';

    /** @customize API endpoints */
    private readonly ENDPOINTS = {
        login: '/Authentication/PostLogin',
        profile: '/Authentication/Get_user_profile',
        refresh: '/Authentication/Post_refresh_token',
        changePassword: '/Authentication/Post_change_password'
    };

    /** @customize Route after logout */
    private readonly LOGIN_ROUTE = '/login';

    // ============================================
    // STATE
    // ============================================

    /** Current authenticated user */
    private _currentUser = signal<UserProfile | null>(null);

    /** Loading state */
    private _loading = signal(false);

    /** Error state */
    private _error = signal<string | null>(null);

    /** Password change required flag */
    private _requiresPasswordChange = signal(false);

    // ============================================
    // COMPUTED
    // ============================================

    /** Current user (readonly) */
    readonly currentUser = this._currentUser.asReadonly();

    /** Authentication status */
    readonly isAuthenticated = computed(() =>
        this.tokenService.hasValidToken(this.appId) && this._currentUser() !== null
    );

    /** Loading state */
    readonly loading = this._loading.asReadonly();

    /** Error message */
    readonly error = this._error.asReadonly();

    /** Password change required */
    readonly requiresPasswordChange = this._requiresPasswordChange.asReadonly();

    // ============================================
    // PUBLIC API
    // ============================================

    /**
     * Configure the app ID for multi-app environments
     * @param appId Application identifier
     */
    configure(appId: string): void {
        this.appId = appId;
        // Check if already authenticated
        if (this.tokenService.hasValidToken(appId)) {
            this.loadUserProfile().subscribe();
        }
    }

    /**
     * Login with credentials
     * @param credentials Login credentials
     * @returns Observable of login response
     */
    login(credentials: LoginRequest): Observable<LoginResponse> {
        this._loading.set(true);
        this._error.set(null);

        return this.api.post<LoginResponse>(this.ENDPOINTS.login, credentials).pipe(
            tap(response => {
                // Save tokens
                this.tokenService.saveTokenApp(response.access_Token, this.appId);

                if (response.refresh_Token) {
                    this.tokenService.saveRefreshToken(response.refresh_Token, this.appId);
                }

                // Check for password change requirement
                this._requiresPasswordChange.set(response.b_CAMBIO_CONTRASENIA ?? false);

                // Set user if included in response
                if (response.user) {
                    this._currentUser.set(response.user);
                }

                // Set auth header for future requests
                this.api.setAuthToken(response.access_Token);
            }),
            switchMap(response => {
                // Load full profile if not included
                if (!response.user) {
                    return this.loadUserProfile().pipe(
                        switchMap(() => of(response))
                    );
                }
                return of(response);
            }),
            tap(() => this._loading.set(false)),
            catchError(error => {
                this._loading.set(false);
                this._error.set(error.message || 'Error de autenticación');
                return throwError(() => error);
            })
        );
    }

    /**
     * Load user profile from API
     * @returns Observable of user profile
     */
    loadUserProfile(): Observable<UserProfile> {
        const userId = this.tokenService.getUserId(this.appId);

        return this.api.get<{ value: UserProfile }>(
            `${this.ENDPOINTS.profile}?I_ID_USER=${userId}`
        ).pipe(
            tap(response => {
                this._currentUser.set(response.value);
            }),
            switchMap(response => of(response.value))
        );
    }

    /**
     * Refresh access token using refresh token
     * @returns Observable of new login response
     */
    refreshToken(): Observable<LoginResponse> {
        const accessToken = this.tokenService.getTokenApp(this.appId);
        const refreshToken = this.tokenService.getRefreshToken(this.appId);

        if (!accessToken || !refreshToken) {
            return throwError(() => new Error('No tokens available'));
        }

        const request: RefreshTokenRequest = {
            v_ACCESS_TOKEN: accessToken,
            v_REFRESH_TOKEN: refreshToken
        };

        return this.api.post<LoginResponse>(this.ENDPOINTS.refresh, request).pipe(
            tap(response => {
                this.tokenService.saveTokenApp(response.access_Token, this.appId);

                if (response.refresh_Token) {
                    this.tokenService.saveRefreshToken(response.refresh_Token, this.appId);
                }

                this.api.setAuthToken(response.access_Token);
            }),
            catchError(error => {
                // If refresh fails, force logout
                this.logout();
                return throwError(() => error);
            })
        );
    }

    /**
     * Logout and clear all session data
     * @param redirect Whether to redirect to login page (default: true)
     */
    logout(redirect = true): void {
        this.tokenService.removeTokenApp(this.appId);
        this._currentUser.set(null);
        this._error.set(null);
        this.api.setAuthToken('');

        if (redirect) {
            this.router.navigate([this.LOGIN_ROUTE]);
        }
    }

    /**
     * Check if current token is about to expire
     * @returns true if token expires within 5 minutes
     */
    isTokenExpiring(): boolean {
        const token = this.tokenService.getTokenApp(this.appId);
        if (!token) return true;

        return this.tokenService.isTokenExpired(token, 5 * 60 * 1000);
    }

    /**
     * Get current access token
     * @returns Current token or null
     */
    getToken(): string | null {
        return this.tokenService.getTokenApp(this.appId);
    }

    /**
     * Clear error state
     */
    clearError(): void {
        this._error.set(null);
    }
}

import { Component, inject, signal, computed, OnInit, PLATFORM_ID } from '@angular/core';
import { isPlatformBrowser } from '@angular/common';

import { Router } from '@angular/router';
import {
  LayoutShellComponent,
  TopbarComponent,
  SidebarComponent,
  SidebarUser,
  PanelComponent,
  RowComponent,
  AvatarComponent,
  TextComponent,
  ButtonComponent,
  SkeletonComponent,
  MetricsGridComponent,
  ThemeSwitcherComponent,
  ApiService,
  useApi,
  KpiMetric
} from '@shared/ui';

/**
 * User info interface
 * @customize Adjust to match your API response
 */
interface User {
  id: string;
  name: string;
  email: string;
  role?: string;
  avatar?: string;
}

/**
 * Dashboard stats interface
 * @customize Adjust to match your API response
 */
interface DashboardStats {
  totalUsers: number;
  activeProjects: number;
  pendingTasks: number;
  revenue: number;
}

/**
 * Menu item interface for sidebar navigation
 */
interface MenuItem {
  id?: string;
  label: string;
  icon: string;
  route?: string;
  badge?: number | string;
  children?: MenuItem[];
}

/**
 * Dashboard Page Blueprint
 *
 * Features:
 * - LayoutShell with responsive sidebar
 * - Topbar with user menu and notifications
 * - Dynamic sidebar navigation
 * - Stats cards with API integration
 * - Loading states and error handling
 * - Dark mode support
 *
 * @usage
 * 1. Copy this folder to your project's pages directory
 * 2. Update imports to match your project structure
 * 3. Configure menu items and API endpoints
 * 4. Add route in app.routes.ts with auth guard
 */
@Component({
  selector: 'app-dashboard-page',
  standalone: true,
  imports: [
    LayoutShellComponent,
    TopbarComponent,
    SidebarComponent,
    PanelComponent,
    RowComponent,
    AvatarComponent,
    TextComponent,
    ButtonComponent,
    SkeletonComponent,
    MetricsGridComponent,
    ThemeSwitcherComponent
],
  templateUrl: './dashboard-page.component.html',
  styleUrl: './dashboard-page.component.css'
})
export class DashboardPageComponent implements OnInit {
  private api = inject(ApiService);
  private router = inject(Router);
  private platformId = inject(PLATFORM_ID);

  // ============================================
  // CONFIGURATION - Customize these values
  // ============================================

  /** @customize Set your API base URL */
  private readonly API_BASE_URL = 'https://api.example.com/v1';

  /** @customize Token storage key */
  private readonly TOKEN_KEY = 'auth_token';

  // ============================================
  // STATE
  // ============================================

  /** Sidebar visibility state */
  sidebarVisible = signal(true);

  /** Current active menu item */
  activeMenuItem = signal<string>('dashboard');

  /** User info */
  currentUser = signal<User | null>(null);

  /** Dashboard stats API hook */
  statsApi = useApi<DashboardStats>();

  /** Metrics dataset for dashboard indicators */
  metrics = computed<KpiMetric[]>(() => {
    const stats = this.statsApi.data();
    return [
      {
        title: 'Total Usuarios',
        subtitle: 'Base acumulada',
        value: stats?.totalUsers ?? 0,
        format: 'compact',
        trend: 'up',
        trendValue: '+12%',
        comparisonLabel: 'vs. mes pasado',
        iconClass: 'fa-solid fa-users',
        series: [8.4, 8.7, 9.1, 9.4, 9.8, 10.1, 10.6],
      },
      {
        title: 'Proyectos Activos',
        subtitle: 'Sprint vigente',
        value: stats?.activeProjects ?? 0,
        format: 'number',
        trend: 'up',
        trendValue: '+4',
        comparisonLabel: 'nuevos esta semana',
        iconClass: 'fa-solid fa-folder-open',
        series: [17, 18, 19, 19, 20, 21, 22],
      },
      {
        title: 'Tareas Pendientes',
        subtitle: 'Backlog operativo',
        value: stats?.pendingTasks ?? 0,
        format: 'number',
        trend: 'down',
        trendValue: '-9%',
        comparisonLabel: 'mejorando SLA',
        iconClass: 'fa-solid fa-clock',
        series: [56, 52, 49, 45, 44, 41, 39],
      },
      {
        title: 'Ingresos',
        subtitle: 'Facturación mensual',
        value: stats?.revenue ?? 0,
        format: 'currency',
        currency: 'PEN',
        trend: 'up',
        trendValue: '+8.5%',
        comparisonLabel: 'objetivo trimestral',
        iconClass: 'fa-solid fa-sack-dollar',
        series: [180, 195, 202, 215, 228, 235, 244],
      },
    ];
  });

  // ============================================
  // MENU CONFIGURATION
  // ============================================

  /** @customize Configure your menu items */
  menuItems: MenuItem[] = [
    {
      id: 'dashboard',
      label: 'Dashboard',
      icon: 'fa-solid fa-chart-pie',
      route: '/dashboard'
    },
    {
      id: 'crud',
      label: 'CRUD',
      icon: 'fa-solid fa-users',
      route: '/crud',
      badge: 5
    },
    {
      id: 'projects',
      label: 'Proyectos',
      icon: 'fa-solid fa-folder-open',
      route: '/dashboard/projects'
    },
    {
      id: 'reports',
      label: 'Reportes',
      icon: 'fa-solid fa-chart-bar',
      route: '/dashboard/reports'
    },
    {
      id: 'settings',
      label: 'Configuración',
      icon: 'fa-solid fa-gear',
      route: '/dashboard/settings'
    }
  ];

  // ============================================
  // COMPUTED
  // ============================================

  /** User initials for avatar */
  userInitials = computed(() => {
    const user = this.currentUser();
    if (!user?.name) return 'U';
    return user.name
      .split(' ')
      .map(n => n[0])
      .join('')
      .toUpperCase()
      .slice(0, 2);
  });

  /** Adapted user for sidebar */
  sidebarUser = computed<SidebarUser | null>(() => {
    const u = this.currentUser();
    if (!u) return null;
    return {
      name: u.name,
      role: u.role || 'User',
      initials: this.userInitials(),
      photo: u.avatar
    };
  });

  // ============================================
  // LIFECYCLE
  // ============================================

  constructor() {
    this.api.setBaseUrl(this.API_BASE_URL);
    this.loadUserFromStorage();
    this.setupAuthToken();
  }

  ngOnInit(): void {
    this.loadDashboardStats();
  }

  // ============================================
  // INITIALIZATION
  // ============================================

  private loadUserFromStorage(): void {
    if (!isPlatformBrowser(this.platformId)) return;

    const userJson = localStorage.getItem('user') || sessionStorage.getItem('user');
    if (userJson) {
      try {
        this.currentUser.set(JSON.parse(userJson));
      } catch {
        console.error('Failed to parse user from storage');
      }
    }
  }

  private setupAuthToken(): void {
    if (!isPlatformBrowser(this.platformId)) return;

    const token = localStorage.getItem(this.TOKEN_KEY) || sessionStorage.getItem(this.TOKEN_KEY);
    if (token) {
      this.api.setAuthToken(token);
    } else {
      // No token, redirect to login
      this.router.navigate(['/login']);
    }
  }

  // ============================================
  // API CALLS
  // ============================================

  loadDashboardStats(): void {
    this.statsApi.execute(
      this.api.get<DashboardStats>('/dashboard/stats')
    );
  }

  // ============================================
  // SIDEBAR ACTIONS
  // ============================================

  toggleSidebar(): void {
    this.sidebarVisible.update(v => !v);
  }

  closeSidebar(): void {
    this.sidebarVisible.set(false);
  }

  onMenuItemClick(item: MenuItem): void {
    this.activeMenuItem.set(item.id || item.label);

    if (item.route) {
      this.router.navigate([item.route]);
    }

    // Close sidebar on mobile
    if (isPlatformBrowser(this.platformId) && window.innerWidth <= 768) {
      this.closeSidebar();
    }
  }

  isMenuItemActive(itemId: string): boolean {
    return this.activeMenuItem() === itemId;
  }

  // ============================================
  // USER ACTIONS
  // ============================================

  onUserAction(action: string): void {
    switch (action) {
      case 'profile':
        this.router.navigate(['/dashboard/profile']);
        break;
      case 'settings':
        this.router.navigate(['/dashboard/settings']);
        break;
      case 'change-password':
        this.router.navigate(['/dashboard/change-password']);
        break;
      default:
        // TODO: Implementar logging service para acciones desconocidas
        break;
    }
  }

  onLogout(): void {
    // Clear stored data
    if (isPlatformBrowser(this.platformId)) {
      localStorage.removeItem(this.TOKEN_KEY);
      localStorage.removeItem('user');
      sessionStorage.removeItem(this.TOKEN_KEY);
      sessionStorage.removeItem('user');
    }

    // Clear API auth
    this.api.clearAuthToken();

    // Redirect to login
    this.router.navigate(['/login']);
  }

  // ============================================
  // STATS HELPERS
  // ============================================

  formatNumber(value: number): string {
    if (value >= 1000000) {
      return (value / 1000000).toFixed(1) + 'M';
    }
    if (value >= 1000) {
      return (value / 1000).toFixed(1) + 'K';
    }
    return value.toString();
  }

  formatCurrency(value: number): string {
    return new Intl.NumberFormat('es-PE', {
      style: 'currency',
      currency: 'PEN',
      minimumFractionDigits: 0
    }).format(value);
  }
}

import { Injectable, signal } from '@angular/core';

export type ModalSize = 'sm' | 'md' | 'lg' | 'xl';

export interface ModalButton {
  label: string;
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
