} from '@shared/ui';

/**
 * Respuesta del endpoint de registro
 * @customize Ajustar según tu API
 */
interface RegisterResponse {
  message: string;
  userId?: string;
}

/**
 * Register Page Blueprint
 *
 * Flujo completo de registro:
 * - Nombre, apellido, email, contraseña con confirmación
 * - Aceptar términos y condiciones
 * - Manejo de errores inline con AlertComponent
 * - Validaciones reactivas
 *
 * @usage
 * 1. Copiar esta carpeta al directorio `pages/` de tu proyecto
 * 2. Ajustar la interface RegisterResponse
 * 3. Configurar el endpoint `REGISTER_ENDPOINT`
 * 4. Agregar ruta en app.routes.ts con `canActivate: [guestGuard]`
 */
const REGISTER_ENDPOINT = '/Authentication/Register';

@Component({
  selector: 'app-register-page',
  standalone: true,
  imports: [
    ReactiveFormsModule,
    AuthLayoutComponent,
    FloatingInputComponent,
    ButtonComponent,
    FormErrorComponent,
    PanelComponent,
    TextComponent,
    RowComponent,
    FormRowComponent,
    AlertComponent,
    CheckboxComponent,
    DividerComponent
],
  templateUrl: './register-page.component.html',
  styleUrl: './register-page.component.css',
})
export class RegisterPageComponent {
  private readonly fb     = inject(FormBuilder);
  private readonly router = inject(Router);
  private readonly api    = inject(ApiService);

  protected readonly registerApi = useApi<RegisterResponse>();
  protected registered = signal(false);

  protected form = this.fb.group({
    firstName: ['', [Validators.required, Validators.minLength(2)]],
    lastName:  ['', [Validators.required, Validators.minLength(2)]],
    email:     ['', [Validators.required, Validators.email]],
    password:  ['', [Validators.required, Validators.minLength(8)]],
    confirm:   ['', Validators.required],
    terms:     [false, Validators.requiredTrue],
  }, { validators: this.matchPasswords });

  constructor() {
    // Redirigir al login tras registro exitoso
    effect(() => {
      if (this.registerApi.success()) {
        this.registered.set(true);
      }
    });
  }

  private matchPasswords(group: import('@angular/forms').AbstractControl) {
    const pw  = group.get('password')?.value;
    const cpw = group.get('confirm')?.value;
    return pw === cpw ? null : { passwordMismatch: true };
  }

  protected onSubmit(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    const { firstName, lastName, email, password } = this.form.value;
    this.registerApi.execute(
      this.api.post<RegisterResponse>(REGISTER_ENDPOINT, { firstName, lastName, email, password })
    );
  }

  protected goToLogin(): void {
    this.router.navigate(['/login']);
  }

  // Helpers de acceso al form
  get f() { return this.form.controls; }
}

import { Component, inject, signal, effect } from '@angular/core';

import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import {
  AuthLayoutComponent,
  FloatingInputComponent,
  ButtonComponent,
  ApiService,
  useApi,
  PanelComponent,
  TextComponent,
  FormRowComponent,
  AlertComponent,
  DividerComponent,
} from '@shared/ui';

/** Paso actual del flujo de recuperación */
type Step = 'request' | 'sent' | 'reset' | 'done';

/** Respuesta de la API al solicitar reset */
interface ForgotResponse {
  message: string;
}

/** Respuesta de la API al confirmar nueva contraseña */
interface ResetResponse {
  message: string;
}

/**
 * Forgot Password Page Blueprint
 *
 * Flujo de 4 pasos:
 * 1. request — el usuario ingresa su email
 * 2. sent    — confirmación de envío de correo
 * 3. reset   — el usuario ingresa código + nueva contraseña
 * 4. done    — confirmación de restablecimiento
 *
 * @usage
 * 1. Copiar al directorio `pages/` de tu proyecto
 * 2. Configurar `FORGOT_ENDPOINT` y `RESET_ENDPOINT`
 * 3. Agregar ruta en app.routes.ts con `canActivate: [guestGuard]`
 */
const FORGOT_ENDPOINT = '/Authentication/ForgotPassword';
const RESET_ENDPOINT  = '/Authentication/ResetPassword';

@Component({
  selector: 'app-forgot-password-page',
  standalone: true,
  imports: [
    ReactiveFormsModule,
    AuthLayoutComponent,
    FloatingInputComponent,
    ButtonComponent,
    PanelComponent,
    TextComponent,
    FormRowComponent,
    AlertComponent,
    DividerComponent
],
  templateUrl: './forgot-password-page.component.html',
  styleUrl:    './forgot-password-page.component.css',
})
export class ForgotPasswordPageComponent {
  private readonly fb     = inject(FormBuilder);
  private readonly router = inject(Router);
  private readonly api    = inject(ApiService);

  protected step = signal<Step>('request');

  protected forgotApi = useApi<ForgotResponse>();
  protected resetApi  = useApi<ResetResponse>();

  /** Formulario paso 1: email */
  protected emailForm = this.fb.group({
    email: ['', [Validators.required, Validators.email]],
  });

  /** Formulario paso 3: código + nueva contraseña */
  protected resetForm = this.fb.group({
    code:     ['', Validators.required],
    password: ['', [Validators.required, Validators.minLength(8)]],
    confirm:  ['', Validators.required],
  }, { validators: this.matchPasswords });

  constructor() {
    effect(() => {
      if (this.forgotApi.success()) this.step.set('sent');
    });
    effect(() => {
      if (this.resetApi.success()) this.step.set('done');
    });
  }

  private matchPasswords(group: import('@angular/forms').AbstractControl) {
    const pw  = group.get('password')?.value;
    const cpw = group.get('confirm')?.value;
    return pw === cpw ? null : { passwordMismatch: true };
  }

  protected submitEmail(): void {
    if (this.emailForm.invalid) { this.emailForm.markAllAsTouched(); return; }
    this.forgotApi.execute(
      this.api.post<ForgotResponse>(FORGOT_ENDPOINT, { email: this.emailForm.value.email })
    );
  }

  protected submitReset(): void {
    if (this.resetForm.invalid) { this.resetForm.markAllAsTouched(); return; }
    const { code, password } = this.resetForm.value;
    this.resetApi.execute(
      this.api.post<ResetResponse>(RESET_ENDPOINT, {
        email: this.emailForm.value.email,
        token: code,
        newPassword: password,
      })
    );
  }

  protected goToLogin(): void {
    this.router.navigate(['/login']);
  }

  protected resend(): void {
    this.forgotApi.reset();
    this.submitEmail();
  }

  get ef() { return this.emailForm.controls; }
  get rf() { return this.resetForm.controls; }
}

import { Component, inject, signal, OnInit, PLATFORM_ID } from '@angular/core';
import { isPlatformBrowser } from '@angular/common';

import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import {
  LayoutShellComponent,
  TopbarComponent,
  SidebarComponent,
  SidebarMenuItem,
  PanelComponent,
  RowComponent,
  AvatarComponent,
  TextComponent,
  ButtonComponent,
  FloatingInputComponent,
  FormRowComponent,
  DividerComponent,
  AlertComponent,
  ChipComponent,
  SkeletonComponent,
  ThemeSwitcherComponent,
  AuthService,
  ApiService,
  useApi,
} from '@shared/ui';

/** Perfil del usuario
 * @customize Ajusta según tu API */
interface UserProfile {
  id:        string;
  firstName: string;
  lastName:  string;
  email:     string;
  role?:     string;
  phone?:    string;
  avatar?:   string;
}

/** Respuesta al guardar perfil */
interface SaveProfileResponse {
  message: string;
}

/** Respuesta al cambiar contraseña */
interface ChangePasswordResponse {
  message: string;
}

const PROFILE_ENDPOINT         = '/Users/GetProfile';
const SAVE_PROFILE_ENDPOINT    = '/Users/UpdateProfile';
const CHANGE_PASSWORD_ENDPOINT = '/Authentication/ChangePassword';

/**
 * Profile Page Blueprint
 *
 * Secciones:
 * - Información personal (nombre, apellido, teléfono)
 * - Cambio de contraseña
 * - Resumen de cuenta (email, rol)
 *
 * @usage
 * 1. Copiar al directorio `pages/` de tu proyecto
 * 2. Ajustar interfaces y endpoints
 * 3. Agregar ruta en app.routes.ts con `canActivate: [authGuard]`
 */
@Component({
  selector: 'app-profile-page',
  standalone: true,
  imports: [
    ReactiveFormsModule,
    LayoutShellComponent,
    TopbarComponent,
    SidebarComponent,
    PanelComponent,
    RowComponent,
    AvatarComponent,
    TextComponent,
    ButtonComponent,
    FloatingInputComponent,
    FormRowComponent,
    DividerComponent,
    AlertComponent,
    ChipComponent,
    SkeletonComponent,
    ThemeSwitcherComponent
],
  templateUrl: './profile-page.component.html',
  styleUrl:    './profile-page.component.css',
})
export class ProfilePageComponent implements OnInit {
  private readonly fb         = inject(FormBuilder);
  private readonly router     = inject(Router);
  private readonly platformId = inject(PLATFORM_ID);
  private readonly api        = inject(ApiService);
  private readonly auth       = inject(AuthService);

  protected sidebarVisible = signal(true);

  protected profileApi     = useApi<UserProfile>();
  protected saveApi        = useApi<SaveProfileResponse>();
  protected passwordApi    = useApi<ChangePasswordResponse>();

  protected saveSuccess    = signal(false);
  protected passSuccess    = signal(false);

  /** Formulario de datos personales */
  protected infoForm = this.fb.group({
    firstName: ['', [Validators.required, Validators.minLength(2)]],
    lastName:  ['', [Validators.required, Validators.minLength(2)]],
    phone:     [''],
  });

  /** Formulario de cambio de contraseña */
  protected passForm = this.fb.group({
    current:  ['', Validators.required],
    password: ['', [Validators.required, Validators.minLength(8)]],
    confirm:  ['', Validators.required],
  }, { validators: this.matchPasswords });

  // ── Sidebar menu ──────────────────────────────────
  protected readonly menuItems: SidebarMenuItem[] = [
    { label: 'Dashboard',  icon: 'fa-solid fa-gauge',      route: '/dashboard' },
    { label: 'Perfil',     icon: 'fa-solid fa-user',       active: true },
    { label: 'Cerrar sesión', icon: 'fa-solid fa-right-from-bracket' },
  ];

  ngOnInit(): void {
    if (isPlatformBrowser(this.platformId)) {
      this.sidebarVisible.set(window.innerWidth >= 768);
    }
    this.loadProfile();
  }

  private loadProfile(): void {
    this.profileApi.execute(
      this.api.get<UserProfile>(PROFILE_ENDPOINT)
    );
    // Cuando lleguen los datos, popular el formulario
    const sub = this.profileApi.data;
    // Effect manual: watch data signal change
    const fill = () => {
      const profile = this.profileApi.data();
      if (profile) {
        this.infoForm.patchValue({
          firstName: profile.firstName,
          lastName:  profile.lastName,
          phone:     profile.phone ?? '',
        });
      }
    };
    // Poll once after execute (signals are synchronous in most cases)
    setTimeout(fill, 100);
    void sub; // suppress unused warning
  }

  protected saveProfile(): void {
    if (this.infoForm.invalid) { this.infoForm.markAllAsTouched(); return; }
    this.saveSuccess.set(false);
    this.saveApi.execute(
      this.api.put<SaveProfileResponse>(SAVE_PROFILE_ENDPOINT, this.infoForm.value)
    );
    // Mostrar éxito
    setTimeout(() => { if (this.saveApi.success()) this.saveSuccess.set(true); }, 300);
  }

  protected changePassword(): void {
    if (this.passForm.invalid) { this.passForm.markAllAsTouched(); return; }
    this.passSuccess.set(false);
    const { current, password } = this.passForm.value;
    this.passwordApi.execute(
      this.api.post<ChangePasswordResponse>(CHANGE_PASSWORD_ENDPOINT, {
        currentPassword: current,
        newPassword: password,
      })
    );
    setTimeout(() => {
      if (this.passwordApi.success()) {
        this.passSuccess.set(true);
        this.passForm.reset();
      }
    }, 300);
  }

  protected logout(): void {
    this.auth.logout();
    this.router.navigate(['/login']);
  }

  protected onToggleSidebar(): void {
    this.sidebarVisible.update(v => !v);
  }

  private matchPasswords(group: import('@angular/forms').AbstractControl) {
    const pw  = group.get('password')?.value;
    const cpw = group.get('confirm')?.value;
    return pw === cpw ? null : { passwordMismatch: true };
  }

  get uf() { return this.infoForm.controls; }
  get pf() { return this.passForm.controls; }
  get currentUser() { return this.auth.currentUser(); }
}

import {
  Component, Input, Output, EventEmitter, signal, HostListener,
  ElementRef, forwardRef, inject, ChangeDetectionStrategy
} from '@angular/core';

import { ControlValueAccessor, NG_VALUE_ACCESSOR, FormsModule } from '@angular/forms';
import { TranslateModule } from '@ngx-translate/core';

export interface Select2Option {
  value: string | number;
  label: string;
  icon?: string;
  disabled?: boolean;
}

@Component({
  // Standalone component for Select2 dropdown
  selector: 'app-select2',
  standalone: true,
  imports: [FormsModule, TranslateModule],
  changeDetection: ChangeDetectionStrategy.OnPush,
  providers: [{
    provide: NG_VALUE_ACCESSOR,
    useExisting: forwardRef(() => Select2Component),
    multi: true
  }],
  template: `
    <div 
      class="select2-wrapper"
      [class.open]="isOpen()"
      [class.disabled]="disabled"
      [class.focused]="isOpen()"
      [class.has-value]="hasValue()"
      [class.multiple]="multiple"
      [class.has-label]="label"
      [style.width]="width || null"
    >
      <div class="select2-trigger" 
        (click)="toggleDropdown()" 
        (keydown)="handleKeydown($event)"
        [attr.aria-labelledby]="label ? selectId() : null"
        [attr.aria-controls]="listboxId()"
        [attr.aria-activedescendant]="highlightedIndex() >= 0 ? optionId(highlightedIndex()) : null"
        tabindex="0"
        role="combobox"
        [attr.aria-expanded]="isOpen()"
      >
        @if (label) {
          <!-- eslint-disable-next-line @angular-eslint/template/label-has-associated-control -->
          <label class="floating-label" [id]="selectId()">{{ label }}</label>
        }
        <!-- Single value display -->
        @if (!multiple) {
          <span class="select2-value">
            @if (selectedOption()) {
              @if (selectedOption()!.icon) {
                <span class="option-icon">{{ selectedOption()!.icon }}</span>
              }
              {{ selectedOption()!.label | translate }}
            } @else if (!label) {
              <span class="placeholder">{{ placeholder | translate }}</span>
            }
          </span>
        }
        
        <!-- Multiple values as tags -->
        @if (multiple) {
          <div class="select2-tags">
            @for (opt of selectedOptions(); track opt.value) {
              <span class="select2-tag">
                {{ opt.label | translate }}
                <button type="button" class="tag-remove" (click)="removeTag(opt, $event)">×</button>
              </span>
            }
            @if (selectedOptions().length === 0 && !label) {
              <span class="placeholder">{{ placeholder | translate }}</span>
            }
          </div>
        }
        
        <span class="select2-arrow">
          <svg width="12" height="12" viewBox="0 0 12 12" fill="none">
            <path d="M2 4L6 8L10 4" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
          </svg>
        </span>
      </div>

      @if (isOpen()) {
        <div class="select2-dropdown">
          <!-- Search box -->
          @if (searchable) {
            <div class="select2-search">
              <input 
                type="text" 
                class="search-input" 
                placeholder="Buscar..."
                [ngModel]="searchTerm()"
                (ngModelChange)="searchTerm.set($event)"
                (click)="$event.stopPropagation()"
                (keydown)="handleKeydown($event)"
              />
              <span class="search-icon">🔍</span>
            </div>
          }
          
          <!-- Options list -->
          <div class="select2-options" role="listbox" [id]="listboxId()">
            @for (option of filteredOptions(); track option.value; let i = $index) {
              <div 
                [id]="optionId(i)"
                class="select2-option"
                [class.selected]="isSelected(option)"
                [class.highlighted]="highlightedIndex() === i"
                [class.disabled]="option.disabled"
                (click)="!option.disabled && selectOption(option)"
                (keydown)="handleKeydown($event)"
                tabindex="-1"
                role="option"
                [attr.aria-selected]="isSelected(option)"
              >
                @if (option.icon) {
                  <span class="option-icon">{{ option.icon }}</span>
                }
                <span class="option-label">{{ option.label | translate }}</span>
                @if (isSelected(option)) {
                  <span class="check-icon">✓</span>
                }
              </div>
            } @empty {
              <div class="select2-no-results">No hay resultados</div>
            }
          </div>
        </div>
      }
    </div>
  `,
  styles: [`
    :host {
      display: block;
      width: 100%;
    }

    .select2-wrapper {
      position: relative;
      width: 100%;
      min-width: 15rem;
    }

    .select2-wrapper.disabled {
      opacity: 0.6;
      pointer-events: none;
    }

    .select2-wrapper.has-label {
      margin-top: var(--space-3);
    }

    /* === TRIGGER === */
    .select2-trigger {
      position: relative;
      display: flex;
      align-items: center;
      height: var(--control-height);
      padding: var(--space-1) var(--space-3);
      padding-right: 2.75rem;
      background: var(--input-bg);
      border: var(--input-border-width, 1.5px) solid var(--input-border);
      border-radius: var(--radius-md);
      cursor: pointer;
      transition: all 200ms ease;
      font-size: var(--text-sm);
      box-sizing: border-box;
      box-shadow: var(--input-shadow);
    }

    .select2-wrapper.has-label .select2-trigger {
      padding: var(--space-1) var(--space-3);
    }

    /* === FLOATING LABEL === */
    .floating-label {
      position: absolute;
      left: var(--space-3);
      top: 50%;
      transform: translateY(-50%);
      font-size: var(--text-sm);
      color: var(--input-placeholder);
      pointer-events: none;
      transition: all 200ms cubic-bezier(0.4, 0, 0.2, 1);
      background: var(--input-bg);
      padding: 0 var(--space-2);
      white-space: nowrap;
    }

    .select2-wrapper.focused .floating-label,
    .select2-wrapper.has-value .floating-label {
      top: -0.625rem;
      transform: translateY(0);
      font-size: var(--text-xs);
      font-weight: 500;
      color: var(--primary-color);
    }

    /* === MULTI-SELECT FIX === */
    .select2-wrapper.multiple .select2-trigger {
      min-height: var(--control-height);
      height: auto;
      padding: var(--space-1) var(--space-3);
      padding-right: 2.75rem;
      align-items: center;
    }

    .select2-wrapper.focused .select2-trigger,
    .select2-trigger:hover {
      border-color: var(--input-border-focus);
    }

    .select2-wrapper.focused .select2-trigger {
      box-shadow: var(--shadow-focus-primary);
    }

    .select2-value {
      display: flex;
      align-items: center;
      gap: var(--space-2);
      flex: 1;
      font-size: var(--text-sm);
      color: var(--input-text);
      line-height: normal;
    }

    .placeholder {
      color: var(--input-placeholder);
    }

    .select2-arrow {
      position: absolute;
      right: var(--space-3);
      top: 50%;
      transform: translateY(-50%);
      color: var(--text-color-secondary);
      transition: transform 200ms ease;
    }

    .select2-wrapper.open .select2-arrow {
      transform: translateY(-50%) rotate(180deg);
    }

    /* === TAGS (Multiple) === */
    .select2-tags {
      display: flex;
      flex-wrap: wrap;
      gap: var(--space-1);
      flex: 1;
      padding: var(--space-1) 0;
    }

    .select2-tag {
      display: inline-flex;
      align-items: center;
      gap: var(--space-1);
      padding: var(--space-1) var(--space-2);
      background: var(--primary-color-lighter);
      color: var(--primary-color);
      border-radius: var(--radius-full);
      font-size: var(--text-xs);
      font-weight: 500;
    }

    .tag-remove {
      display: flex;
      align-items: center;
      justify-content: center;
      width: 1rem;
      height: 1rem;
      padding: 0;
      background: none;
      border: none;
      border-radius: 50%;
      font-size: var(--text-sm);
      color: var(--primary-color);
      cursor: pointer;
      transition: all 150ms ease;
    }

    .tag-remove:hover {
      background: var(--primary-color-lighter);
    }

    /* === DROPDOWN === */
    .select2-dropdown {
      position: absolute;
