  col2: string;
  col3: string;
  col4: string;
  col5: string;
  col6: string;
  col7: string;
  col9: string;
  statusVariant: 'default' | 'primary' | 'secondary' | 'success' | 'warning' | 'error';
}

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [
    FormsModule,
    ScrollOverlayComponent,
    ThemeSwitcherComponent,
    UiShowcaseComponent,
    PanelComponent,
    TableActionsComponent,
    LayoutShellComponent,
