],
  templateUrl: './app.html',
  styleUrl: './app.css',
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class App {
  private readonly platformId = inject(PLATFORM_ID);
  private readonly translate = inject(TranslateService);
  private readonly MOBILE_BREAKPOINT = 768;

  protected readonly title = signal('app.title');

  constructor() {
    // Initialize translation language
    const savedLang = isPlatformBrowser(this.platformId)
      ? localStorage.getItem('app-language')
      : null;
    this.translate.use(savedLang || 'es');
    this.generateData();
  }

  // Filtros
  filterDateStart = '';
  filterDateEnd = '';
  floatingInputValue = '';
  // Floating Input value

  // Opciones para el select de estado
  statusOptions: Select2Option[] = [
    { value: '', label: 'filters.statusOptions.all' },
    { value: 'data.status.active', label: 'filters.statusOptions.active' },
    { value: 'data.status.pending', label: 'filters.statusOptions.pending' },
    { value: 'data.status.inactive', label: 'filters.statusOptions.inactive' }
  ];
  filterStatus: string | number = '';

  // Método para obtener variante de chip según estado (Claves i18n)
  getStatusClass(statusKey: string): 'default' | 'primary' | 'secondary' | 'success' | 'warning' | 'error' {
    const statusMap: Record<string, 'default' | 'primary' | 'secondary' | 'success' | 'warning' | 'error'> = {
      'data.status.active': 'success',
      'data.status.completed': 'success',
      'data.status.approved': 'success',
      'data.status.pending': 'warning',
      'data.status.review': 'secondary',
      'data.status.inactive': 'error'
    };
    return statusMap[statusKey] || 'default';
  }

  // Event handlers placeholder
  onFilter() {
    // Filtering logic
  }

  onClear() {
    this.filterStatus = '';
    this.filterDateStart = '';
    this.filterDateEnd = '';
    this.floatingInputValue = '';
  }

  // Sidebar toggle - inicia oculto en móvil
  sidebarVisible = signal(this.getInitialSidebarState());

  menuItems: SidebarMenuItem[] = [
    { label: 'Dashboard', icon: 'fa-solid fa-chart-pie', route: '/' },
    { label: 'Showcase', icon: 'fa-solid fa-layer-group', route: '/showcase' },
    { label: 'Settings', icon: 'fa-solid fa-gear', route: '/settings' }
  ];

  private getInitialSidebarState(): boolean {
    if (isPlatformBrowser(this.platformId)) {
      return window.innerWidth > this.MOBILE_BREAKPOINT;
    }
    return true; // Default visible for SSR
  }

  @HostListener('window:resize')
  onWindowResize(): void {
    if (isPlatformBrowser(this.platformId)) {
      const isMobile = window.innerWidth <= this.MOBILE_BREAKPOINT;
      // Auto-hide on mobile, auto-show on desktop
      if (isMobile && this.sidebarVisible()) {
        this.sidebarVisible.set(false);
      } else if (!isMobile && !this.sidebarVisible()) {
        this.sidebarVisible.set(true);
      }
    }
  }

  onToggleSidebar() {
    this.sidebarVisible.update(v => !v);
  }

  onSidebarNavigate() {
    // Only auto-close on mobile (breakpoint 768px matches CSS)
    if (isPlatformBrowser(this.platformId) && window.innerWidth <= 768) {
      this.sidebarVisible.set(false);
    }
  }

  // Logout handler
  onLogout() {
    // Auth service logout
    alert('Cerrando sesión...');
  }

  onView(_row: TableRow) { }
  onEdit(_row: TableRow) { }
  onDelete(_row: TableRow) { }

  // Datos de ejemplo con claves de traducción
  private nombres = ['Juan Pérez', 'María García', 'Carlos López', 'Ana Martínez', 'Pedro Sánchez', 'Laura Torres', 'Diego Ramírez', 'Sofia Herrera'];
  private estados = ['data.status.active', 'data.status.pending', 'data.status.completed', 'data.status.review', 'data.status.approved'];
  private tipos = ['data.type.fua', 'data.type.prescription', 'data.type.order', 'data.type.consultation', 'data.type.referral'];
  private prioridades = ['data.priority.high', 'data.priority.medium', 'data.priority.low'];

  // Cantidad de filas
  rowCount = signal(25);

  protected readonly tableData = signal<TableRow[]>([]);


  updateRowCount(count: string | number) {
    const value = Number(count);
    if (!isNaN(value) && value > 0) {
      this.rowCount.set(value);
      this.generateData();
    }
  }

  private generateData() {
    const count = this.rowCount();
    const data = Array.from({ length: count }, (_, i) => {
      const nombre = this.nombres[i % this.nombres.length];
      const email = nombre.toLowerCase().replace(' ', '.').replace(/á/g, 'a').replace(/é/g, 'e').replace(/í/g, 'i').replace(/ó/g, 'o').replace(/ú/g, 'u') + '@email.com';
      const statusKey = this.estados[i % this.estados.length];
      return {
        col1: `${1001 + i}`,
        col2: nombre,
        col3: email,
        col4: `${String(Math.floor(Math.random() * 28) + 1).padStart(2, '0')}/12/2024`,
        col5: statusKey, // Ahora es una key
        col6: this.tipos[i % this.tipos.length],
        col7: `S/ ${(Math.random() * 500 + 50).toFixed(2)}`,
        col9: this.prioridades[i % this.prioridades.length],
        statusVariant: this.getStatusClass(statusKey)
      };
    });
    this.tableData.set(data);
  }

}

import {
  Component,
  Input,
  Output,
  EventEmitter,
  forwardRef,
  signal,
  ChangeDetectionStrategy,
} from '@angular/core';

import { ControlValueAccessor, NG_VALUE_ACCESSOR, FormsModule } from '@angular/forms';
import { ChipComponent } from '../../atoms/chip/chip.component';

export interface TagInputOption {
  label: string;
  value: string;
}

/**
 * TagInputComponent — Campo de entrada con etiquetas/chips removibles.
 * Compatible con `ngModel` y `FormControl`.
 *
 * @example
 * ```html
 * <app-tag-input
 *   [(ngModel)]="tags"
 *   label="Etiquetas"
 *   placeholder="Escribe y presiona Enter"
 *   [maxTags]="5"
 * ></app-tag-input>
 * ```
 */
@Component({
  selector: 'app-tag-input',
  standalone: true,
  imports: [FormsModule, ChipComponent],
  changeDetection: ChangeDetectionStrategy.OnPush,
  providers: [
    {
      provide: NG_VALUE_ACCESSOR,
      useExisting: forwardRef(() => TagInputComponent),
      multi: true,
    },
  ],
  template: `
    <div class="tag-input-wrapper" [class.tag-input--disabled]="disabled" [class.tag-input--focused]="focused()">
      @if (label) {
        <label class="tag-input__label">{{ label }}</label>
      }
      <div class="tag-input__field">
        <!-- Tags -->
        @for (tag of tags(); track tag) {
          <app-chip
            size="sm"
            variant="primary"
            [removable]="!disabled"
            (remove)="removeTag(tag)"
          >{{ tag }}</app-chip>
        }

        <!-- Input -->
        @if (!maxTags || tags().length < maxTags) {
          <input
            #inputEl
            class="tag-input__input"
            [placeholder]="tags().length === 0 ? placeholder : ''"
            [disabled]="disabled"
            [(ngModel)]="inputValue"
            (keydown)="onKeydown($event)"
            (focus)="focused.set(true)"
            (blur)="onBlur()"
            [attr.aria-label]="label || placeholder"
          />
        }
      </div>

      @if (hint) {
        <span class="tag-input__hint">{{ hint }}</span>
      }
      @if (error) {
        <span class="tag-input__error">{{ error }}</span>
      }
    </div>
  `,
  styles: [`
    :host { display: block; width: 100%; }

    .tag-input__label {
      display: block;
      margin-bottom: var(--space-1);
      font-size: var(--text-sm);
      font-weight: var(--font-medium, 500);
      color: var(--text-color-secondary);
    }

    .tag-input__field {
      display: flex;
      flex-wrap: wrap;
      align-items: center;
      gap: var(--space-1);
      min-height: 42px;
      padding: var(--space-2) var(--space-3);
      border: 1px solid var(--border-color);
      border-radius: var(--radius-md);
      background: var(--input-background, var(--surface-background));
      cursor: text;
      transition: border-color 150ms ease, box-shadow 150ms ease;
    }

    .tag-input--focused .tag-input__field {
      border-color: var(--primary-color);
      box-shadow: 0 0 0 3px var(--primary-color-alpha, rgba(59,130,246,0.15));
    }

    .tag-input--disabled .tag-input__field {
      opacity: 0.6;
      cursor: not-allowed;
      background: var(--surface-section);
    }

    .tag-input__input {
      flex: 1;
      min-width: 80px;
      border: none;
      outline: none;
      background: transparent;
      font-size: var(--text-sm);
      color: var(--text-color);
      padding: 2px 0;
    }

    .tag-input__hint {
      display: block;
      margin-top: var(--space-1);
      font-size: var(--text-xs);
      color: var(--text-color-muted);
    }

    .tag-input__error {
      display: block;
      margin-top: var(--space-1);
      font-size: var(--text-xs);
      color: var(--color-danger-600, #dc2626);
    }
  `],
})
export class TagInputComponent implements ControlValueAccessor {
  @Input() label = '';
  @Input() placeholder = 'Agregar etiqueta…';
  @Input() hint = '';
  @Input() error = '';
  @Input() maxTags: number | null = null;
  @Input() allowDuplicates = false;
  @Input() disabled = false;
  @Input() separator: string[] = ['Enter', ','];

  @Output() tagAdded = new EventEmitter<string>();
  @Output() tagRemoved = new EventEmitter<string>();

  protected tags = signal<string[]>([]);
  protected focused = signal(false);
  protected inputValue = '';

  private onChange: (value: string[]) => void = () => {};
  private onTouched: () => void = () => {};

  writeValue(value: string[]): void {
    this.tags.set(Array.isArray(value) ? value : []);
  }

  registerOnChange(fn: (value: string[]) => void): void {
    this.onChange = fn;
  }

  registerOnTouched(fn: () => void): void {
    this.onTouched = fn;
  }

  setDisabledState(isDisabled: boolean): void {
    this.disabled = isDisabled;
  }

  onKeydown(event: KeyboardEvent): void {
    if (this.separator.includes(event.key)) {
      event.preventDefault();
      this.addTag();
    } else if (event.key === 'Backspace' && !this.inputValue && this.tags().length) {
      const current = this.tags();
      this.removeTag(current[current.length - 1]);
    }
  }

  onBlur(): void {
    this.focused.set(false);
    if (this.inputValue.trim()) {
      this.addTag();
    }
    this.onTouched();
  }

  private addTag(): void {
    const value = this.inputValue.trim().replace(/,$/, '');
    if (!value) return;
    if (!this.allowDuplicates && this.tags().includes(value)) {
      this.inputValue = '';
      return;
    }
    if (this.maxTags && this.tags().length >= this.maxTags) return;

    const newTags = [...this.tags(), value];
    this.tags.set(newTags);
    this.inputValue = '';
    this.onChange(newTags);
    this.tagAdded.emit(value);
  }

  removeTag(tag: string): void {
    const newTags = this.tags().filter(t => t !== tag);
    this.tags.set(newTags);
    this.onChange(newTags);
    this.tagRemoved.emit(tag);
  }
}

import {
  Component, Input, ChangeDetectionStrategy
} from '@angular/core';


export type TimelineItemStatus = 'completed' | 'active' | 'pending' | 'error';

export interface TimelineItem {
  id?: string | number;
  title: string;
  description?: string;
  date?: string;
  status?: TimelineItemStatus;
  icon?: string;
  badge?: string;
