import { Injectable, signal, computed, PLATFORM_ID, inject } from '@angular/core';
import { isPlatformBrowser } from '@angular/common';

/**
 * Token configuration for multi-app environments
 */
export interface TokenConfig {
    /** Application ID for token isolation */
    appId: string;
    /** Token expiry buffer in milliseconds (default: 5 minutes) */
    expiryBuffer?: number;
    /** Use secure cookies (HTTPS only) */
    secure?: boolean;
}

/**
 * Decoded JWT payload structure
 */
export interface JwtPayload {
    exp?: number;
    iat?: number;
    sub?: string;
    [key: string]: unknown;
}

/**
 * TokenService - Secure token management with cookies
 * 
 * Features:
 * - Cookie-based token storage (more secure than localStorage for XSS)
 * - Multi-app support with isolated tokens
 * - Automatic token expiry detection
 * - SSR-safe implementation
 * 
 * @usage
 * ```typescript
 * // Inject service
 * private tokenService = inject(TokenService);
 * 
 * // Save token for app
 * tokenService.saveTokenApp('jwt-token', '2');
 * 
 * // Get token
 * const token = tokenService.getTokenApp('2');
 * 
 * // Check if valid
 * if (tokenService.hasValidToken('2')) { ... }
 * 
 * // Clear on logout
 * tokenService.removeTokenApp('2');
 * ```
 */
@Injectable({
    providedIn: 'root'
})
export class TokenService {
    private platformId = inject(PLATFORM_ID);

    // ============================================
    // CONFIGURATION
    // ============================================

    /** Default expiry buffer: 5 minutes before actual expiry */
    private readonly DEFAULT_EXPIRY_BUFFER = 5 * 60 * 1000;

    /** Cookie path */
    private readonly COOKIE_PATH = '/';

    /** Token cookie prefix */
    private readonly TOKEN_PREFIX = 'app_token_';

    /** Refresh token cookie prefix */
    private readonly REFRESH_PREFIX = 'app_refresh_';

    // ============================================
    // STATE
    // ============================================

    /** Current app ID being used */
    private currentAppId = signal<string | null>(null);

    /** Whether browser environment is available */
    private readonly isBrowser = computed(() => isPlatformBrowser(this.platformId));

    // ============================================
    // PUBLIC API - Token Operations
    // ============================================

    /**
     * Save access token for a specific application
     * @param token JWT access token
     * @param appId Application identifier
     * @param expiresInSeconds Optional expiry in seconds (defaults to token's exp claim)
     */
    saveTokenApp(token: string, appId: string, expiresInSeconds?: number): void {
        if (!this.isBrowser()) return;

        const cookieName = this.getTokenCookieName(appId);
        let expiry: Date | undefined;

        if (expiresInSeconds) {
            expiry = new Date(Date.now() + expiresInSeconds * 1000);
        } else {
            // Try to extract expiry from JWT
            const payload = this.decodeToken(token);
            if (payload?.exp) {
                expiry = new Date(payload.exp * 1000);
            }
        }

        this.setCookie(cookieName, token, expiry);
        this.currentAppId.set(appId);
    }

    /**
     * Save refresh token for a specific application
     * @param token Refresh token
     * @param appId Application identifier
     * @param expiresInDays Optional expiry in days (default: 30)
     */
    saveRefreshToken(token: string, appId: string, expiresInDays = 30): void {
        if (!this.isBrowser()) return;

        const cookieName = this.getRefreshCookieName(appId);
        const expiry = new Date(Date.now() + expiresInDays * 24 * 60 * 60 * 1000);

        this.setCookie(cookieName, token, expiry);
    }

    /**
     * Get access token for a specific application
     * @param appId Application identifier
     * @returns Token string or null if not found
     */
    getTokenApp(appId: string): string | null {
        if (!this.isBrowser()) return null;

        const cookieName = this.getTokenCookieName(appId);
        return this.getCookie(cookieName);
    }

    /**
     * Get refresh token for a specific application
     * @param appId Application identifier
     * @returns Refresh token string or null
     */
    getRefreshToken(appId: string): string | null {
        if (!this.isBrowser()) return null;

        const cookieName = this.getRefreshCookieName(appId);
        return this.getCookie(cookieName);
    }

    /**
     * Remove all tokens for a specific application (logout)
     * @param appId Application identifier
     */
    removeTokenApp(appId: string): void {
        if (!this.isBrowser()) return;

        this.deleteCookie(this.getTokenCookieName(appId));
        this.deleteCookie(this.getRefreshCookieName(appId));

        if (this.currentAppId() === appId) {
            this.currentAppId.set(null);
        }
    }

    /**
     * Check if a valid (non-expired) token exists for an app
     * @param appId Application identifier
     * @returns true if valid token exists
     */
    hasValidToken(appId: string): boolean {
        const token = this.getTokenApp(appId);
        if (!token) return false;

        return !this.isTokenExpired(token);
    }

    /**
     * Check if token is expired or about to expire
     * @param token JWT token string
     * @param bufferMs Buffer before expiry (default: 5 minutes)
     * @returns true if expired or expiring soon
     */
    isTokenExpired(token: string, bufferMs = this.DEFAULT_EXPIRY_BUFFER): boolean {
        const payload = this.decodeToken(token);
        if (!payload?.exp) return false; // Can't determine, assume valid

        const expiryTime = payload.exp * 1000;
        const now = Date.now();

        return now >= (expiryTime - bufferMs);
    }

    /**
     * Decode JWT token payload (without verification)
     * @param token JWT token string
     * @returns Decoded payload or null
     */
    decodeToken(token: string): JwtPayload | null {
        try {
            const parts = token.split('.');
            if (parts.length !== 3) return null;

            const payload = parts[1];
            const decoded = atob(payload.replace(/-/g, '+').replace(/_/g, '/'));
            return JSON.parse(decoded);
        } catch {
            return null;
        }
    }

    /**
     * Get user ID from token
     * @param appId Application identifier
     * @returns User ID or null
     */
    getUserId(appId: string): string | null {
        const token = this.getTokenApp(appId);
        if (!token) return null;

        const payload = this.decodeToken(token);
        return payload?.sub ?? null;
    }

    // ============================================
    // LEGACY API (for backward compatibility)
    // ============================================

    /**
     * @deprecated Use saveTokenApp instead
     */
    saveToken(value: string): void {
        this.setCookie('value-token', value);
    }

    /**
     * @deprecated Use getTokenApp instead
     */
    getToken(): string | null {
        return this.getCookie('value-token');
    }

    // ============================================
    // PRIVATE - Cookie Operations
    // ============================================

    private getTokenCookieName(appId: string): string {
        return `${this.TOKEN_PREFIX}${appId}`;
    }

    private getRefreshCookieName(appId: string): string {
        return `${this.REFRESH_PREFIX}${appId}`;
    }

    private setCookie(name: string, value: string, expires?: Date, secure = false): void {
        if (!this.isBrowser()) return;

        let cookie = `${encodeURIComponent(name)}=${encodeURIComponent(value)}`;
        cookie += `; path=${this.COOKIE_PATH}`;

        if (expires) {
            cookie += `; expires=${expires.toUTCString()}`;
        }

        if (secure || location.protocol === 'https:') {
            cookie += '; secure';
        }

        // SameSite for CSRF protection
        cookie += '; SameSite=Strict';

        document.cookie = cookie;
    }

    private getCookie(name: string): string | null {
        if (!this.isBrowser()) return null;

        const nameEQ = encodeURIComponent(name) + '=';
        const cookies = document.cookie.split(';');

        for (const cookie of cookies) {
            const c = cookie.trim();
            if (c.indexOf(nameEQ) === 0) {
                return decodeURIComponent(c.substring(nameEQ.length));
            }
        }

        return null;
    }

    private deleteCookie(name: string): void {
        if (!this.isBrowser()) return;

        document.cookie = `${encodeURIComponent(name)}=; path=${this.COOKIE_PATH}; expires=Thu, 01 Jan 1970 00:00:00 GMT`;
    }
}

import { Injectable, signal, computed } from '@angular/core';
import { Observable, Subscription } from 'rxjs';
import { ApiError } from './api.service';

/**
 * Estado de una petición API
 */
export interface ApiState<T> {
  data: T | null;
  loading: boolean;
  error: ApiError | null;
}

/**
 * Resultado del hook useApi
 */
export interface UseApiResult<T> {
  /** Signal con los datos de la respuesta */
  data: () => T | null;
  /** Signal que indica si está cargando */
  loading: () => boolean;
  /** Signal con el error si existe */
  error: () => ApiError | null;
  /** Signal computed que indica si la petición fue exitosa */
  success: () => boolean;
  /** Signal computed que indica si hay error */
  hasError: () => boolean;
  /** Ejecuta una petición */
  execute: (request: Observable<T>) => Subscription;
  /** Resetea el estado */
  reset: () => void;
  /** Actualiza los datos manualmente */
  setData: (data: T) => void;
}

/**
 * Hook signal-based para consumir APIs con estado reactivo.
 * 
 * @example
 * ```typescript
 * // En tu componente
 * private api = inject(ApiService);
 * private userApi = useApi<User[]>();
 * 
 * // Acceso a signals
 * users = this.userApi.data;
 * loading = this.userApi.loading;
 * error = this.userApi.error;
 * 
 * // Ejecutar petición
 * loadUsers() {
 *   this.userApi.execute(this.api.get('/users'));
 * }
 * 
 * // En template
 * @if (loading()) {
 *   <app-loader></app-loader>
 * } @else if (error()) {
 *   <p>Error: {{ error()?.message }}</p>
 * } @else {
 *   @for (user of users(); track user.id) {
 *     <p>{{ user.name }}</p>
 *   }
 * }
 * ```
 */
export function useApi<T>(initialData: T | null = null): UseApiResult<T> {
  const data = signal<T | null>(initialData);
  const loading = signal<boolean>(false);
  const error = signal<ApiError | null>(null);

  const success = computed(() => data() !== null && !loading() && !error());
  const hasError = computed(() => error() !== null);

  let currentSubscription: Subscription | null = null;

  const execute = (request: Observable<T>): Subscription => {
    // Cancel previous request if exists
    if (currentSubscription) {
      currentSubscription.unsubscribe();
    }

    loading.set(true);
    error.set(null);

    currentSubscription = request.subscribe({
      next: (result) => {
        data.set(result);
        loading.set(false);
      },
      error: (err: ApiError) => {
        error.set(err);
        loading.set(false);
      }
    });

    return currentSubscription;
  };

  const reset = (): void => {
    if (currentSubscription) {
      currentSubscription.unsubscribe();
      currentSubscription = null;
    }
    data.set(initialData);
    loading.set(false);
    error.set(null);
  };

  const setData = (newData: T): void => {
    data.set(newData);
    error.set(null);
  };

  return {
    data: data.asReadonly(),
    loading: loading.asReadonly(),
    error: error.asReadonly(),
    success,
    hasError,
    execute,
    reset,
    setData
  };
}

/**
 * Servicio inyectable alternativo para usar con DI.
 * Útil cuando necesitas compartir estado entre componentes.
 * 
 * @example
 * ```typescript
 * // Crear servicio específico
 * @Injectable({ providedIn: 'root' })
 * export class UsersApiService extends UseApiService<User[]> {
 *   private api = inject(ApiService);
 *   
 *   loadUsers() {
 *     this.execute(this.api.get('/users'));
 *   }
 * }
 * ```
 */
@Injectable()
export class UseApiService<T> {
  private readonly _data = signal<T | null>(null);
  private readonly _loading = signal<boolean>(false);
  private readonly _error = signal<ApiError | null>(null);
  private subscription: Subscription | null = null;

  readonly data = this._data.asReadonly();
  readonly loading = this._loading.asReadonly();
  readonly error = this._error.asReadonly();
  readonly success = computed(() => this._data() !== null && !this._loading() && !this._error());
  readonly hasError = computed(() => this._error() !== null);

  execute(request: Observable<T>): Subscription {
    if (this.subscription) {
      this.subscription.unsubscribe();
    }

    this._loading.set(true);
    this._error.set(null);

    this.subscription = request.subscribe({
      next: (result) => {
        this._data.set(result);
        this._loading.set(false);
      },
      error: (err: ApiError) => {
        this._error.set(err);
        this._loading.set(false);
      }
    });

    return this.subscription;
  }

  reset(): void {
    if (this.subscription) {
      this.subscription.unsubscribe();
      this.subscription = null;
    }
    this._data.set(null);
    this._loading.set(false);
    this._error.set(null);
  }

  setData(data: T): void {
    this._data.set(data);
    this._error.set(null);
  }
}

import { Component, inject, signal, computed, OnInit, PLATFORM_ID } from '@angular/core';
import { isPlatformBrowser } from '@angular/common';

import { Router } from '@angular/router';
import {
  LayoutShellComponent,
  TopbarComponent,
  SidebarComponent,
  SidebarUser,
  PanelComponent,
  RowComponent,
  AvatarComponent,
  TextComponent,
  ButtonComponent,
  SkeletonComponent,
  MetricsGridComponent,
  ThemeSwitcherComponent,
  ApiService,
  useApi,
  KpiMetric
} from '@shared/ui';

/**
 * User info interface
 * @customize Adjust to match your API response
 */
interface User {
  id: string;
  name: string;
  email: string;
  role?: string;
  avatar?: string;
}

/**
 * Dashboard stats interface
 * @customize Adjust to match your API response
 */
interface DashboardStats {
  totalUsers: number;
  activeProjects: number;
  pendingTasks: number;
  revenue: number;
}

/**
 * Menu item interface for sidebar navigation
 */
interface MenuItem {
  id?: string;
  label: string;
  icon: string;
  route?: string;
  badge?: number | string;
  children?: MenuItem[];
}

/**
 * Dashboard Page Blueprint
 *
 * Features:
 * - LayoutShell with responsive sidebar
 * - Topbar with user menu and notifications
 * - Dynamic sidebar navigation
 * - Stats cards with API integration
 * - Loading states and error handling
 * - Dark mode support
 *
 * @usage
 * 1. Copy this folder to your project's pages directory
 * 2. Update imports to match your project structure
 * 3. Configure menu items and API endpoints
 * 4. Add route in app.routes.ts with auth guard
 */
@Component({
  selector: 'app-dashboard-page',
  standalone: true,
  imports: [
    LayoutShellComponent,
    TopbarComponent,
    SidebarComponent,
    PanelComponent,
    RowComponent,
    AvatarComponent,
    TextComponent,
    ButtonComponent,
    SkeletonComponent,
    MetricsGridComponent,
    ThemeSwitcherComponent
],
  templateUrl: './dashboard-page.component.html',
  styleUrl: './dashboard-page.component.css'
})
export class DashboardPageComponent implements OnInit {
  private api = inject(ApiService);
  private router = inject(Router);
  private platformId = inject(PLATFORM_ID);

  // ============================================
  // CONFIGURATION - Customize these values
  // ============================================

  /** @customize Set your API base URL */
  private readonly API_BASE_URL = 'https://api.example.com/v1';

  /** @customize Token storage key */
  private readonly TOKEN_KEY = 'auth_token';

  // ============================================
  // STATE
  // ============================================

  /** Sidebar visibility state */
  sidebarVisible = signal(true);

  /** Current active menu item */
  activeMenuItem = signal<string>('dashboard');

  /** User info */
  currentUser = signal<User | null>(null);

  /** Dashboard stats API hook */
  statsApi = useApi<DashboardStats>();

  /** Metrics dataset for dashboard indicators */
  metrics = computed<KpiMetric[]>(() => {
    const stats = this.statsApi.data();
    return [
      {
        title: 'Total Usuarios',
        subtitle: 'Base acumulada',
        value: stats?.totalUsers ?? 0,
        format: 'compact',
        trend: 'up',
        trendValue: '+12%',
        comparisonLabel: 'vs. mes pasado',
        iconClass: 'fa-solid fa-users',
        series: [8.4, 8.7, 9.1, 9.4, 9.8, 10.1, 10.6],
      },
      {
        title: 'Proyectos Activos',
        subtitle: 'Sprint vigente',
        value: stats?.activeProjects ?? 0,
        format: 'number',
        trend: 'up',
        trendValue: '+4',
        comparisonLabel: 'nuevos esta semana',
        iconClass: 'fa-solid fa-folder-open',
        series: [17, 18, 19, 19, 20, 21, 22],
      },
      {
        title: 'Tareas Pendientes',
        subtitle: 'Backlog operativo',
        value: stats?.pendingTasks ?? 0,
        format: 'number',
        trend: 'down',
        trendValue: '-9%',
        comparisonLabel: 'mejorando SLA',
        iconClass: 'fa-solid fa-clock',
        series: [56, 52, 49, 45, 44, 41, 39],
      },
      {
        title: 'Ingresos',
        subtitle: 'Facturación mensual',
        value: stats?.revenue ?? 0,
        format: 'currency',
        currency: 'PEN',
        trend: 'up',
        trendValue: '+8.5%',
        comparisonLabel: 'objetivo trimestral',
        iconClass: 'fa-solid fa-sack-dollar',
        series: [180, 195, 202, 215, 228, 235, 244],
      },
    ];
  });

  // ============================================
  // MENU CONFIGURATION
  // ============================================

  /** @customize Configure your menu items */
  menuItems: MenuItem[] = [
    {
      id: 'dashboard',
      label: 'Dashboard',
      icon: 'fa-solid fa-chart-pie',
      route: '/dashboard'
    },
    {
      id: 'crud',
      label: 'CRUD',
      icon: 'fa-solid fa-users',
      route: '/crud',
      badge: 5
    },
    {
      id: 'projects',
      label: 'Proyectos',
      icon: 'fa-solid fa-folder-open',
      route: '/dashboard/projects'
    },
    {
      id: 'reports',
      label: 'Reportes',
      icon: 'fa-solid fa-chart-bar',
      route: '/dashboard/reports'
    },
    {
      id: 'settings',
      label: 'Configuración',
      icon: 'fa-solid fa-gear',
      route: '/dashboard/settings'
    }
  ];

  // ============================================
  // COMPUTED
  // ============================================

  /** User initials for avatar */
  userInitials = computed(() => {
    const user = this.currentUser();
    if (!user?.name) return 'U';
    return user.name
      .split(' ')
      .map(n => n[0])
      .join('')
      .toUpperCase()
      .slice(0, 2);
  });

  /** Adapted user for sidebar */
  sidebarUser = computed<SidebarUser | null>(() => {
    const u = this.currentUser();
    if (!u) return null;
    return {
      name: u.name,
      role: u.role || 'User',
      initials: this.userInitials(),
      photo: u.avatar
    };
  });

  // ============================================
  // LIFECYCLE
  // ============================================

  constructor() {
    this.api.setBaseUrl(this.API_BASE_URL);
    this.loadUserFromStorage();
    this.setupAuthToken();
  }

  ngOnInit(): void {
    this.loadDashboardStats();
  }

  // ============================================
  // INITIALIZATION
  // ============================================

  private loadUserFromStorage(): void {
    if (!isPlatformBrowser(this.platformId)) return;

    const userJson = localStorage.getItem('user') || sessionStorage.getItem('user');
    if (userJson) {
      try {
        this.currentUser.set(JSON.parse(userJson));
      } catch {
        console.error('Failed to parse user from storage');
      }
    }
  }

  private setupAuthToken(): void {
    if (!isPlatformBrowser(this.platformId)) return;

    const token = localStorage.getItem(this.TOKEN_KEY) || sessionStorage.getItem(this.TOKEN_KEY);
    if (token) {
      this.api.setAuthToken(token);
    } else {
      // No token, redirect to login
      this.router.navigate(['/login']);
    }
  }

  // ============================================
  // API CALLS
  // ============================================

  loadDashboardStats(): void {
    this.statsApi.execute(
      this.api.get<DashboardStats>('/dashboard/stats')
    );
  }

  // ============================================
  // SIDEBAR ACTIONS
  // ============================================

  toggleSidebar(): void {
    this.sidebarVisible.update(v => !v);
  }

  closeSidebar(): void {
    this.sidebarVisible.set(false);
  }

  onMenuItemClick(item: MenuItem): void {
    this.activeMenuItem.set(item.id || item.label);

    if (item.route) {
      this.router.navigate([item.route]);
    }

    // Close sidebar on mobile
    if (isPlatformBrowser(this.platformId) && window.innerWidth <= 768) {
      this.closeSidebar();
    }
  }

  isMenuItemActive(itemId: string): boolean {
    return this.activeMenuItem() === itemId;
  }

  // ============================================
  // USER ACTIONS
  // ============================================

  onUserAction(action: string): void {
    switch (action) {
      case 'profile':
        this.router.navigate(['/dashboard/profile']);
        break;
      case 'settings':
        this.router.navigate(['/dashboard/settings']);
        break;
      case 'change-password':
        this.router.navigate(['/dashboard/change-password']);
        break;
      default:
        // TODO: Implementar logging service para acciones desconocidas
        break;
    }
  }

  onLogout(): void {
    // Clear stored data
    if (isPlatformBrowser(this.platformId)) {
      localStorage.removeItem(this.TOKEN_KEY);
      localStorage.removeItem('user');
      sessionStorage.removeItem(this.TOKEN_KEY);
      sessionStorage.removeItem('user');
    }

    // Clear API auth
    this.api.clearAuthToken();

    // Redirect to login
    this.router.navigate(['/login']);
  }

  // ============================================
  // STATS HELPERS
  // ============================================

  formatNumber(value: number): string {
    if (value >= 1000000) {
      return (value / 1000000).toFixed(1) + 'M';
    }
    if (value >= 1000) {
      return (value / 1000).toFixed(1) + 'K';
    }
    return value.toString();
  }

  formatCurrency(value: number): string {
    return new Intl.NumberFormat('es-PE', {
      style: 'currency',
      currency: 'PEN',
      minimumFractionDigits: 0
    }).format(value);
  }
}

