export class UserMenuComponent {
  /** User initials for avatar */
  @Input() initials = 'U';

  /** User display name */
  @Input() userName = 'Usuario';

  /** User email */
  @Input() userEmail = 'usuario@email.com';

  /** Menu actions */
  @Input() menuActions: UserMenuAction[] = [
    { id: 'profile', label: 'Mi Perfil', icon: 'fa-solid fa-user' },
    { id: 'settings', label: 'Configuración', icon: 'fa-solid fa-gear' },
    { id: 'password', label: 'Cambiar Contraseña', icon: 'fa-solid fa-key' },
    { id: 'logout', label: 'Cerrar Sesión', icon: 'fa-solid fa-arrow-right-from-bracket', danger: true }
  ];

  /** Action selected event */
  @Output() actionSelected = new EventEmitter<UserMenuAction>();

  /** Logout event (convenience) */
  @Output() logout = new EventEmitter<void>();

  isOpen = signal(false);

  toggle(): void {
    this.isOpen.update(v => !v);
  }

  onAction(action: UserMenuAction): void {
    this.actionSelected.emit(action);
    if (action.id === 'logout') {
      this.logout.emit();
    }
    this.isOpen.set(false);
  }

  @HostListener('document:click', ['$event'])
  onClickOutside(event: MouseEvent): void {
    const target = event.target as HTMLElement;
    if (!target.closest('app-user-menu')) {
      this.isOpen.set(false);
    }
  }
}

import { Component, inject, signal, OnInit, PLATFORM_ID } from '@angular/core';
import { isPlatformBrowser } from '@angular/common';

import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import {
  LayoutShellComponent,
  TopbarComponent,
  SidebarComponent,
  SidebarMenuItem,
  PanelComponent,
  RowComponent,
  AvatarComponent,
  TextComponent,
  ButtonComponent,
  FloatingInputComponent,
  FormRowComponent,
  DividerComponent,
  AlertComponent,
  ChipComponent,
  SkeletonComponent,
  ThemeSwitcherComponent,
  AuthService,
  ApiService,
  useApi,
} from '@shared/ui';

/** Perfil del usuario
 * @customize Ajusta según tu API */
interface UserProfile {
  id:        string;
  firstName: string;
  lastName:  string;
  email:     string;
  role?:     string;
  phone?:    string;
  avatar?:   string;
}

/** Respuesta al guardar perfil */
interface SaveProfileResponse {
  message: string;
}

/** Respuesta al cambiar contraseña */
interface ChangePasswordResponse {
  message: string;
}

const PROFILE_ENDPOINT         = '/Users/GetProfile';
const SAVE_PROFILE_ENDPOINT    = '/Users/UpdateProfile';
const CHANGE_PASSWORD_ENDPOINT = '/Authentication/ChangePassword';

/**
 * Profile Page Blueprint
 *
 * Secciones:
 * - Información personal (nombre, apellido, teléfono)
 * - Cambio de contraseña
 * - Resumen de cuenta (email, rol)
 *
 * @usage
 * 1. Copiar al directorio `pages/` de tu proyecto
 * 2. Ajustar interfaces y endpoints
 * 3. Agregar ruta en app.routes.ts con `canActivate: [authGuard]`
 */
@Component({
  selector: 'app-profile-page',
  standalone: true,
  imports: [
    ReactiveFormsModule,
    LayoutShellComponent,
    TopbarComponent,
    SidebarComponent,
    PanelComponent,
    RowComponent,
    AvatarComponent,
    TextComponent,
    ButtonComponent,
    FloatingInputComponent,
    FormRowComponent,
    DividerComponent,
    AlertComponent,
    ChipComponent,
    SkeletonComponent,
    ThemeSwitcherComponent
],
  templateUrl: './profile-page.component.html',
  styleUrl:    './profile-page.component.css',
})
export class ProfilePageComponent implements OnInit {
  private readonly fb         = inject(FormBuilder);
  private readonly router     = inject(Router);
  private readonly platformId = inject(PLATFORM_ID);
  private readonly api        = inject(ApiService);
  private readonly auth       = inject(AuthService);

  protected sidebarVisible = signal(true);

  protected profileApi     = useApi<UserProfile>();
  protected saveApi        = useApi<SaveProfileResponse>();
  protected passwordApi    = useApi<ChangePasswordResponse>();

  protected saveSuccess    = signal(false);
  protected passSuccess    = signal(false);

  /** Formulario de datos personales */
  protected infoForm = this.fb.group({
    firstName: ['', [Validators.required, Validators.minLength(2)]],
    lastName:  ['', [Validators.required, Validators.minLength(2)]],
    phone:     [''],
  });

  /** Formulario de cambio de contraseña */
  protected passForm = this.fb.group({
    current:  ['', Validators.required],
    password: ['', [Validators.required, Validators.minLength(8)]],
    confirm:  ['', Validators.required],
  }, { validators: this.matchPasswords });

  // ── Sidebar menu ──────────────────────────────────
  protected readonly menuItems: SidebarMenuItem[] = [
    { label: 'Dashboard',  icon: 'fa-solid fa-gauge',      route: '/dashboard' },
    { label: 'Perfil',     icon: 'fa-solid fa-user',       active: true },
    { label: 'Cerrar sesión', icon: 'fa-solid fa-right-from-bracket' },
  ];

  ngOnInit(): void {
    if (isPlatformBrowser(this.platformId)) {
      this.sidebarVisible.set(window.innerWidth >= 768);
    }
    this.loadProfile();
  }

  private loadProfile(): void {
    this.profileApi.execute(
      this.api.get<UserProfile>(PROFILE_ENDPOINT)
    );
    // Cuando lleguen los datos, popular el formulario
    const sub = this.profileApi.data;
    // Effect manual: watch data signal change
    const fill = () => {
      const profile = this.profileApi.data();
      if (profile) {
        this.infoForm.patchValue({
          firstName: profile.firstName,
          lastName:  profile.lastName,
          phone:     profile.phone ?? '',
        });
      }
    };
    // Poll once after execute (signals are synchronous in most cases)
    setTimeout(fill, 100);
    void sub; // suppress unused warning
  }

  protected saveProfile(): void {
    if (this.infoForm.invalid) { this.infoForm.markAllAsTouched(); return; }
    this.saveSuccess.set(false);
    this.saveApi.execute(
      this.api.put<SaveProfileResponse>(SAVE_PROFILE_ENDPOINT, this.infoForm.value)
    );
    // Mostrar éxito
    setTimeout(() => { if (this.saveApi.success()) this.saveSuccess.set(true); }, 300);
  }

  protected changePassword(): void {
    if (this.passForm.invalid) { this.passForm.markAllAsTouched(); return; }
    this.passSuccess.set(false);
    const { current, password } = this.passForm.value;
    this.passwordApi.execute(
      this.api.post<ChangePasswordResponse>(CHANGE_PASSWORD_ENDPOINT, {
        currentPassword: current,
        newPassword: password,
      })
    );
    setTimeout(() => {
      if (this.passwordApi.success()) {
        this.passSuccess.set(true);
        this.passForm.reset();
      }
    }, 300);
  }

  protected logout(): void {
    this.auth.logout();
    this.router.navigate(['/login']);
  }

  protected onToggleSidebar(): void {
    this.sidebarVisible.update(v => !v);
  }

  private matchPasswords(group: import('@angular/forms').AbstractControl) {
    const pw  = group.get('password')?.value;
    const cpw = group.get('confirm')?.value;
    return pw === cpw ? null : { passwordMismatch: true };
  }

  get uf() { return this.infoForm.controls; }
  get pf() { return this.passForm.controls; }
  get currentUser() { return this.auth.currentUser(); }
}

import { Injectable, inject, signal, computed } from '@angular/core';
import { Router } from '@angular/router';
import { Observable, of, throwError } from 'rxjs';
import { tap, catchError, switchMap } from 'rxjs/operators';

import { ApiService } from './api.service';
import { TokenService } from './token.service';

/**
 * User profile structure
 * @customize Adjust to match your API response
 */
export interface UserProfile {
    id: string | number;
    user: string;
    names: string;
    email?: string;
    role?: string;
    [key: string]: unknown;
}

/**
 * Login request structure
 * @customize Adjust to match your API
 */
export interface LoginRequest {
    v_user: string;
    v_password: string;
    v_ip?: string;
}

/**
 * Login response structure
 * @customize Adjust to match your API response
 */
export interface LoginResponse {
    access_Token: string;
    refresh_Token?: string;
    b_CAMBIO_CONTRASENIA?: boolean;
    user?: UserProfile;
}

/**
 * Refresh token request
 */
export interface RefreshTokenRequest {
    v_ACCESS_TOKEN: string;
    v_REFRESH_TOKEN: string;
}

/**
 * AuthService - Authentication management
 * 
 * Features:
 * - Login with username/password
 * - Automatic token refresh
 * - User profile management
 * - Logout and session cleanup
 * - Multi-app authentication support
 * 
 * @usage
 * ```typescript
 * // In component
 * private auth = inject(AuthService);
 * 
 * // Login
 * auth.login({ v_user: 'admin', v_password: '123' }).subscribe();
 * 
 * // Check auth state
 * if (auth.isAuthenticated()) { ... }
 * 
 * // Get current user
 * const user = auth.currentUser();
 * 
 * // Logout
 * auth.logout();
 * ```
 */
@Injectable({
    providedIn: 'root'
})
export class AuthService {
    private api = inject(ApiService);
    private tokenService = inject(TokenService);
    private router = inject(Router);

    // ============================================
    // CONFIGURATION - Customize these values
    // ============================================

    /** @customize Application ID for token storage */
    private appId = '2';

    /** @customize API endpoints */
    private readonly ENDPOINTS = {
        login: '/Authentication/PostLogin',
        profile: '/Authentication/Get_user_profile',
        refresh: '/Authentication/Post_refresh_token',
        changePassword: '/Authentication/Post_change_password'
    };

    /** @customize Route after logout */
    private readonly LOGIN_ROUTE = '/login';

    // ============================================
    // STATE
    // ============================================

    /** Current authenticated user */
    private _currentUser = signal<UserProfile | null>(null);

    /** Loading state */
    private _loading = signal(false);

    /** Error state */
    private _error = signal<string | null>(null);

    /** Password change required flag */
    private _requiresPasswordChange = signal(false);

    // ============================================
    // COMPUTED
    // ============================================

    /** Current user (readonly) */
    readonly currentUser = this._currentUser.asReadonly();

    /** Authentication status */
    readonly isAuthenticated = computed(() =>
        this.tokenService.hasValidToken(this.appId) && this._currentUser() !== null
    );

    /** Loading state */
    readonly loading = this._loading.asReadonly();

    /** Error message */
    readonly error = this._error.asReadonly();

    /** Password change required */
    readonly requiresPasswordChange = this._requiresPasswordChange.asReadonly();

    // ============================================
    // PUBLIC API
    // ============================================

    /**
     * Configure the app ID for multi-app environments
     * @param appId Application identifier
     */
    configure(appId: string): void {
        this.appId = appId;
        // Check if already authenticated
        if (this.tokenService.hasValidToken(appId)) {
            this.loadUserProfile().subscribe();
        }
    }

    /**
     * Login with credentials
     * @param credentials Login credentials
     * @returns Observable of login response
     */
    login(credentials: LoginRequest): Observable<LoginResponse> {
        this._loading.set(true);
        this._error.set(null);

        return this.api.post<LoginResponse>(this.ENDPOINTS.login, credentials).pipe(
            tap(response => {
                // Save tokens
                this.tokenService.saveTokenApp(response.access_Token, this.appId);

                if (response.refresh_Token) {
                    this.tokenService.saveRefreshToken(response.refresh_Token, this.appId);
                }

                // Check for password change requirement
                this._requiresPasswordChange.set(response.b_CAMBIO_CONTRASENIA ?? false);

                // Set user if included in response
                if (response.user) {
                    this._currentUser.set(response.user);
                }

                // Set auth header for future requests
                this.api.setAuthToken(response.access_Token);
            }),
            switchMap(response => {
                // Load full profile if not included
                if (!response.user) {
                    return this.loadUserProfile().pipe(
                        switchMap(() => of(response))
                    );
                }
                return of(response);
            }),
            tap(() => this._loading.set(false)),
            catchError(error => {
                this._loading.set(false);
                this._error.set(error.message || 'Error de autenticación');
                return throwError(() => error);
            })
        );
    }

    /**
     * Load user profile from API
     * @returns Observable of user profile
     */
    loadUserProfile(): Observable<UserProfile> {
        const userId = this.tokenService.getUserId(this.appId);

        return this.api.get<{ value: UserProfile }>(
            `${this.ENDPOINTS.profile}?I_ID_USER=${userId}`
        ).pipe(
            tap(response => {
                this._currentUser.set(response.value);
            }),
            switchMap(response => of(response.value))
        );
    }

    /**
     * Refresh access token using refresh token
     * @returns Observable of new login response
     */
    refreshToken(): Observable<LoginResponse> {
        const accessToken = this.tokenService.getTokenApp(this.appId);
        const refreshToken = this.tokenService.getRefreshToken(this.appId);

        if (!accessToken || !refreshToken) {
            return throwError(() => new Error('No tokens available'));
        }

        const request: RefreshTokenRequest = {
            v_ACCESS_TOKEN: accessToken,
            v_REFRESH_TOKEN: refreshToken
        };

        return this.api.post<LoginResponse>(this.ENDPOINTS.refresh, request).pipe(
            tap(response => {
                this.tokenService.saveTokenApp(response.access_Token, this.appId);

                if (response.refresh_Token) {
                    this.tokenService.saveRefreshToken(response.refresh_Token, this.appId);
                }

                this.api.setAuthToken(response.access_Token);
            }),
            catchError(error => {
                // If refresh fails, force logout
                this.logout();
                return throwError(() => error);
            })
        );
    }

    /**
     * Logout and clear all session data
     * @param redirect Whether to redirect to login page (default: true)
     */
    logout(redirect = true): void {
        this.tokenService.removeTokenApp(this.appId);
        this._currentUser.set(null);
        this._error.set(null);
        this.api.setAuthToken('');

        if (redirect) {
            this.router.navigate([this.LOGIN_ROUTE]);
        }
    }

    /**
     * Check if current token is about to expire
     * @returns true if token expires within 5 minutes
     */
    isTokenExpiring(): boolean {
        const token = this.tokenService.getTokenApp(this.appId);
        if (!token) return true;

        return this.tokenService.isTokenExpired(token, 5 * 60 * 1000);
    }

    /**
     * Get current access token
     * @returns Current token or null
     */
    getToken(): string | null {
        return this.tokenService.getTokenApp(this.appId);
    }

    /**
     * Clear error state
     */
    clearError(): void {
        this._error.set(null);
    }
}

import { Injectable } from '@angular/core';
import { AbstractControl, ValidationErrors } from '@angular/forms';

/**
 * Validation error message configuration.
 */
export interface ValidationMessage {
  key: string;
  message: string | ((params?: Record<string, unknown>) => string);
}

/**
 * Default validation error messages in Spanish.
 */
export const DEFAULT_VALIDATION_MESSAGES: Record<string, string | ((params?: Record<string, unknown>) => string)> = {
  required: 'Este campo es requerido',
  email: 'Ingrese un email válido',
  minlength: (params) => `Mínimo ${params?.['requiredLength'] || 0} caracteres`,
  maxlength: (params) => `Máximo ${params?.['requiredLength'] || 0} caracteres`,
  min: (params) => `El valor mínimo es ${params?.['min'] || 0}`,
  max: (params) => `El valor máximo es ${params?.['max'] || 0}`,
  pattern: 'Formato inválido',
  passwordMismatch: 'Las contraseñas no coinciden',
  invalidDate: 'Fecha inválida',
  futureDate: 'La fecha no puede ser futura',
  pastDate: 'La fecha no puede ser pasada',
  invalidPhone: 'Número de teléfono inválido',
  invalidDNI: 'DNI/Documento inválido',
  invalidRUC: 'RUC inválido',
};

/**
 * Service for handling form validation and error messages.
 * 
 * @example
 * ```typescript
 * // In component
 * constructor(private validationService: ValidationService) {}
 * 
 * getError(control: AbstractControl): string {
 *   return this.validationService.getErrorMessage(control);
 * }
 * ```
 */
@Injectable({
  providedIn: 'root'
})
export class ValidationService {
  private customMessages: Record<string, string | ((params?: Record<string, unknown>) => string)> = {};

  /**
   * Get the first error message for a control.
   */
  getErrorMessage(control: AbstractControl | null): string {
    if (!control || !control.errors || !control.touched) {
      return '';
    }

    const errors = control.errors;
    const firstErrorKey = Object.keys(errors)[0];
    const errorParams = errors[firstErrorKey];

    return this.getMessage(firstErrorKey, errorParams);
  }

  /**
   * Get all error messages for a control.
   */
  getAllErrorMessages(control: AbstractControl | null): string[] {
    if (!control || !control.errors || !control.touched) {
      return [];
    }

    return Object.entries(control.errors).map(([key, params]) =>
      this.getMessage(key, params)
    );
  }

  /**
   * Set custom validation messages.
   */
  setCustomMessages(messages: Record<string, string | ((params?: Record<string, unknown>) => string)>): void {
    this.customMessages = { ...this.customMessages, ...messages };
  }

  /**
   * Get message for a specific error key.
   */
  private getMessage(errorKey: string, params?: unknown): string {
    const message = this.customMessages[errorKey] || DEFAULT_VALIDATION_MESSAGES[errorKey];

    if (!message) {
      return `Error: ${errorKey}`;
    }

    if (typeof message === 'function') {
      return message(params as Record<string, unknown>);
    }

    return message;
  }

  // ============================================
  // Custom Validators
  // ============================================

  /**
   * Validates that passwords match.
   */
  static passwordMatch(passwordField: string, confirmField: string) {
    return (control: AbstractControl): ValidationErrors | null => {
      const password = control.get(passwordField);
      const confirm = control.get(confirmField);

      if (password && confirm && password.value !== confirm.value) {
        confirm.setErrors({ passwordMismatch: true });
        return { passwordMismatch: true };
      }
      return null;
    };
  }

  /**
   * Validates Peruvian DNI format (8 digits).
   */
  static dni(control: AbstractControl): ValidationErrors | null {
    const value = control.value;
    if (!value) return null;

    const dniPattern = /^\d{8}$/;
    return dniPattern.test(value) ? null : { invalidDNI: true };
  }

  /**
   * Validates Peruvian RUC format (11 digits starting with 10 or 20).
   */
  static ruc(control: AbstractControl): ValidationErrors | null {
    const value = control.value;
    if (!value) return null;

    const rucPattern = /^(10|20)\d{9}$/;
    return rucPattern.test(value) ? null : { invalidRUC: true };
  }

  /**
   * Validates phone number format.
   */
  static phone(control: AbstractControl): ValidationErrors | null {
    const value = control.value;
    if (!value) return null;

    // Accepts formats: 9XXXXXXXX, +51 9XXXXXXXX, 01 XXXXXXX
    const phonePattern = /^(\+51\s?)?9\d{8}$|^0[1-9]\s?\d{6,7}$/;
    return phonePattern.test(value.replace(/\s/g, '')) ? null : { invalidPhone: true };
  }

  /**
   * Validates that date is not in the future.
   */
  static notFutureDate(control: AbstractControl): ValidationErrors | null {
    const value = control.value;
    if (!value) return null;

    const inputDate = new Date(value);
    const today = new Date();
    today.setHours(23, 59, 59, 999);

    return inputDate > today ? { futureDate: true } : null;
  }

  /**
   * Validates that date is not in the past.
   */
  static notPastDate(control: AbstractControl): ValidationErrors | null {
    const value = control.value;
    if (!value) return null;

    const inputDate = new Date(value);
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    return inputDate < today ? { pastDate: true } : null;
  }
}

