import { Injectable, signal } from '@angular/core';

export type PopupSize = 'sm' | 'md' | 'lg';
export type PopupType = 'info' | 'success' | 'warning' | 'error' | 'confirm';

export interface PopupButton {
  label: string;
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  action: () => void;
}

export interface PopupConfig {
  id?: number;
  title: string;
  message?: string;
  type?: PopupType;
  size?: PopupSize;
  icon?: string;
  closable?: boolean;
  closeOnBackdrop?: boolean;
  buttons?: PopupButton[];
  /** Contenido HTML personalizado (opcional) */
  htmlContent?: string;
}

export interface PopupItem extends PopupConfig {
  id: number;
  closing?: boolean;
}

/**
 * Servicio global para mostrar popups/modales dinámicos.
 * Inyectable en root para que sea singleton en toda la aplicación.
 * 
 * @example
 * ```typescript
 * export class MyComponent {
 *   private popup = inject(PopupService);
 * 
 *   showInfo() {
 *     this.popup.info('Información', 'Este es un mensaje informativo');
 *   }
 * 
 *   showConfirm() {
 *     this.popup.confirm({
 *       title: '¿Eliminar?',
 *       message: '¿Estás seguro de eliminar este elemento?',
 *       onConfirm: () => this.delete(),
 *       onCancel: () => {}
 *     });
 *   }
 * }
 * ```
 */
@Injectable({
  providedIn: 'root'
})
export class PopupService {
  private popupId = 0;

  /** Signal público para que el componente lea los popups */
  readonly popups = signal<PopupItem[]>([]);

  /**
   * Muestra un popup con la configuración especificada.
   */
  show(config: PopupConfig): number {
    const id = ++this.popupId;
    const popup: PopupItem = {
      ...config,
      id,
      type: config.type ?? 'info',
      size: config.size ?? 'md',
      closable: config.closable ?? true,
      closeOnBackdrop: config.closeOnBackdrop ?? true
    };

    this.popups.update(p => [...p, popup]);
    return id;
  }

  /** Popup informativo simple */
  info(title: string, message: string): number {
    return this.show({
      title,
      message,
      type: 'info',
      icon: 'fa-solid fa-circle-info',
      buttons: [{ label: 'Aceptar', variant: 'primary', action: () => this.close(this.popupId) }]
    });
  }

  /** Popup de éxito */
  success(title: string, message: string): number {
    return this.show({
      title,
      message,
      type: 'success',
      icon: 'fa-solid fa-circle-check',
      buttons: [{ label: 'Aceptar', variant: 'primary', action: () => this.close(this.popupId) }]
    });
  }

  /** Popup de advertencia */
  warning(title: string, message: string): number {
    return this.show({
      title,
      message,
      type: 'warning',
      icon: 'fa-solid fa-triangle-exclamation',
      buttons: [{ label: 'Entendido', variant: 'primary', action: () => this.close(this.popupId) }]
    });
  }

  /** Popup de error */
  error(title: string, message: string): number {
    return this.show({
      title,
      message,
      type: 'error',
      icon: 'fa-solid fa-circle-xmark',
      buttons: [{ label: 'Cerrar', variant: 'danger', action: () => this.close(this.popupId) }]
    });
  }

  /** Popup de confirmación con acciones */
  confirm(options: {
    title: string;
    message: string;
    confirmLabel?: string;
    cancelLabel?: string;
    onConfirm: () => void;
    onCancel?: () => void;
  }): number {
    const id = ++this.popupId;
    return this.show({
      title: options.title,
      message: options.message,
      type: 'confirm',
      icon: 'fa-solid fa-question-circle',
      closeOnBackdrop: false,
      buttons: [
        {
          label: options.cancelLabel ?? 'Cancelar',
          variant: 'ghost',
          action: () => { options.onCancel?.(); this.close(id); }
        },
        {
          label: options.confirmLabel ?? 'Confirmar',
          variant: 'primary',
          action: () => { options.onConfirm(); this.close(id); }
        }
      ]
    });
  }

  /**
   * Cierra un popup específico por ID.
   */
  close(id: number): void {
    this.popups.update(p =>
      p.map(popup => popup.id === id ? { ...popup, closing: true } : popup)
    );
    setTimeout(() => {
      this.popups.update(p => p.filter(popup => popup.id !== id));
    }, 200);
  }

  /** Cierra todos los popups */
  clear(): void {
    this.popups.set([]);
  }
}

import { DestroyRef, inject, Injectable, effect, signal } from '@angular/core';

export type Theme = 'light' | 'dark' | 'brand-dark' | 'system';

@Injectable({
  providedIn: 'root'
})
export class ThemeService {
  private readonly destroyRef = inject(DestroyRef);
  private readonly THEME_STORAGE_KEY = 'app-theme';
  private readonly DARK_CLASS = 'dark';

  // Signal para el tema seleccionado
  private readonly selectedTheme = signal<Theme>(this.getInitialTheme());

  // Signal para el tema efectivo (light, dark, o brand-dark)
  private readonly effectiveTheme = signal<'light' | 'dark' | 'brand-dark'>(this.getEffectiveTheme());

  // Signal para saber si está en dark mode actualmente (cualquier variante oscura)
  readonly isDarkMode = signal<boolean>(
    this.effectiveTheme() === 'dark' || this.effectiveTheme() === 'brand-dark'
  );

  constructor() {
    // Aplicar tema inicial inmediatamente
    if (typeof window !== 'undefined' && typeof document !== 'undefined') {
      this.applyTheme(this.selectedTheme());
    }

    // Efecto: aplicar tema cuando cambia
    effect(() => {
      const theme = this.selectedTheme();
      this.applyTheme(theme);
      this.effectiveTheme.set(this.getEffectiveTheme());
      const effective = this.effectiveTheme();
      this.isDarkMode.set(effective === 'dark' || effective === 'brand-dark');
    });

    // Escuchar cambios en preferencia del SO
    if (typeof window !== 'undefined' && window.matchMedia) {
      const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
      const handleChange = () => {
        if (this.selectedTheme() === 'system') {
          this.effectiveTheme.set(this.getEffectiveTheme());
          const effective = this.effectiveTheme();
          this.isDarkMode.set(effective === 'dark' || effective === 'brand-dark');
          this.applyTheme('system');
        }
      };

      mediaQuery.addEventListener('change', handleChange);

      // Cleanup cuando el servicio se destruye
      this.destroyRef.onDestroy(() => {
        mediaQuery.removeEventListener('change', handleChange);
      });
    }
  }

  /**
   * Obtiene el tema inicial del localStorage o del SO
   */
  private getInitialTheme(): Theme {
    if (typeof window === 'undefined') return 'light';

    const stored = localStorage.getItem(this.THEME_STORAGE_KEY) as Theme | null;
    if (stored && ['light', 'dark', 'brand-dark', 'system'].includes(stored)) {
      return stored;
    }

    return 'system';
  }

  /**
   * Obtiene el tema efectivo considerando preferencia del SO
   */
  private getEffectiveTheme(): 'light' | 'dark' | 'brand-dark' {
    if (typeof window === 'undefined') return 'light';

    const selected = this.selectedTheme();

    if (selected === 'system') {
      return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
    }

    return selected;
  }

  /**
   * Aplica el tema en el DOM y localStorage
   */
  private applyTheme(theme: Theme): void {
    if (typeof window === 'undefined' || typeof document === 'undefined') {
      return;
    }

    const htmlElement = document.documentElement;
    let effectiveTheme: 'light' | 'dark' | 'brand-dark';

    if (theme === 'system') {
      effectiveTheme = this.getEffectiveTheme();
    } else {
      effectiveTheme = theme;
    }

    // Add transitioning class for smooth animation
    htmlElement.classList.add('theme-transitioning');

    // Apply theme class and attribute
    if (effectiveTheme === 'dark') {
      htmlElement.classList.add(this.DARK_CLASS);
      htmlElement.setAttribute('data-theme', 'dark');
    } else if (effectiveTheme === 'brand-dark') {
      htmlElement.classList.add(this.DARK_CLASS); // Also add .dark class for basic tailwind/css dark util support if used
      htmlElement.setAttribute('data-theme', 'brand-dark');
    } else {
      htmlElement.classList.remove(this.DARK_CLASS);
      htmlElement.setAttribute('data-theme', 'light');
    }

    // Remove transitioning class after animation completes
    requestAnimationFrame(() => {
      setTimeout(() => {
        htmlElement.classList.remove('theme-transitioning');
      }, 150); // Match CSS transition duration
    });

    // Save to localStorage
    localStorage.setItem(this.THEME_STORAGE_KEY, theme);
  }

  /**
   * Cambiar a tema claro
   */
  setLightTheme(): void {
    this.selectedTheme.set('light');
  }

  /**
   * Cambiar a tema oscuro
   */
  setDarkTheme(): void {
    this.selectedTheme.set('dark');
  }

  /**
   * Cambiar a tema oscuro (Corporativo)
   */
  setBrandDarkTheme(): void {
    this.selectedTheme.set('brand-dark');
  }

  /**
   * Usar preferencia del SO
   */
  setSystemTheme(): void {
    this.selectedTheme.set('system');
  }

  /**
   * Alternar entre claro y oscuro (por defecto alterna a brand-dark si no es standard)
   */
  toggleTheme(): void {
    if (this.isDarkMode()) {
      this.setLightTheme();
    } else {
      this.setBrandDarkTheme(); // Default to brand dark on toggle
    }
  }

  /**
   * Obtener el tema seleccionado
   */
  getSelectedTheme(): Theme {
    return this.selectedTheme();
  }

  /**
   * Obtener el tema efectivo
   */
  getEffectiveDarkMode(): 'light' | 'dark' | 'brand-dark' {
    return this.effectiveTheme();
  }
}

