import {
  Directive,
  Input,
  TemplateRef,
  ViewContainerRef,
  inject,
  OnInit,
} from '@angular/core';
import { AuthService } from '../services/auth.service';

/**
 * PermissionDirective — Directiva estructural para RBAC (Role-Based Access Control).
 *
 * Muestra o oculta elementos del DOM según el rol del usuario autenticado.
 *
 * @usage
 * ```html
 * <!-- Mostrar solo para admins -->
 * <button *appPermission="'admin'">Eliminar</button>
 *
 * <!-- Mostrar para múltiples roles -->
 * <app-panel *appPermission="['admin', 'manager']">Configuración</app-panel>
 *
 * <!-- Con fallback (else) -->
 * <div *appPermission="'admin'; else noAccess">Panel admin</div>
 * <ng-template #noAccess>
 *   <p>No tienes permiso para ver esto.</p>
 * </ng-template>
 * ```
 *
 * @setup Registrar en app.config.ts:
 * No requiere registro global — es standalone. Solo importar donde se use.
 *
 * @customize
 * Ajusta `hasPermission()` para usar tu modelo de permisos real.
 * Actualmente usa `user.role` del AuthService.
 */
@Directive({
  selector: '[appPermission]',
  standalone: true,
})
export class PermissionDirective implements OnInit {
  private tpl = inject(TemplateRef<unknown>);
  private vcr = inject(ViewContainerRef);
  private auth = inject(AuthService);

  /** Rol o lista de roles permitidos */
  @Input('appPermission') requiredRoles: string | string[] = [];

  /** Template alternativo cuando no tiene permiso */
  @Input('appPermissionElse') elseTemplate?: TemplateRef<unknown>;

  ngOnInit(): void {
    this.updateView();
  }

  private updateView(): void {
    this.vcr.clear();

    if (this.hasPermission()) {
      this.vcr.createEmbeddedView(this.tpl);
    } else if (this.elseTemplate) {
      this.vcr.createEmbeddedView(this.elseTemplate);
    }
  }

  /**
   * Verifica si el usuario tiene el rol requerido.
   * @customize Ajusta esta lógica a tu modelo de permisos.
   */
  private hasPermission(): boolean {
    const user = this.auth.currentUser();
    if (!user) return false;

    const userRole = user['role'] as string | undefined;
    if (!userRole) return false;

    const roles = Array.isArray(this.requiredRoles)
      ? this.requiredRoles
      : [this.requiredRoles];

    // 'superadmin' tiene acceso a todo
    if (userRole === 'superadmin') return true;

    return roles.includes(userRole);
  }
}

import {
  Directive, input, signal, HostListener,
  ElementRef, inject, OnDestroy, PLATFORM_ID,
} from '@angular/core';
import { isPlatformBrowser } from '@angular/common';

export type TooltipPosition = 'top' | 'bottom' | 'left' | 'right';

/**
 * TooltipDirective
 *
 * Uso:
 * ```html
 * <button appTooltip="Copiar" tooltipPosition="top">...</button>
 * ```
 */
@Directive({
  selector: '[appTooltip]',
  standalone: true,
  host: {
    '[attr.data-tooltip]': 'appTooltip()',
    '[attr.data-tooltip-pos]': 'tooltipPosition()',
    'class': 'tooltip-host',
  },
})
export class TooltipDirective implements OnDestroy {
  readonly appTooltip      = input.required<string>();
  readonly tooltipPosition = input<TooltipPosition>('top');

  private readonly el         = inject(ElementRef<HTMLElement>);
  private readonly platformId = inject(PLATFORM_ID);
  private tooltipEl: HTMLElement | null = null;

  @HostListener('mouseenter')
  show(): void {
    if (!isPlatformBrowser(this.platformId)) return;
    const text = this.appTooltip();
    if (!text) return;
    this.tooltipEl = document.createElement('div');
    this.tooltipEl.className = `tooltip tooltip--${this.tooltipPosition()}`;
    this.tooltipEl.textContent = text;
    this.tooltipEl.setAttribute('role', 'tooltip');
    document.body.appendChild(this.tooltipEl);
    this.positionTooltip();
  }

  @HostListener('mouseleave')
  @HostListener('blur')
  hide(): void {
    this.tooltipEl?.remove();
    this.tooltipEl = null;
  }

  ngOnDestroy(): void {
    this.hide();
  }

  private positionTooltip(): void {
    if (!this.tooltipEl) return;
    const rect = this.el.nativeElement.getBoundingClientRect();
    const tip  = this.tooltipEl;
    const pos  = this.tooltipPosition();
    const scrollY = window.scrollY;
    const scrollX = window.scrollX;

    // Temporalmente visible para medir
    tip.style.visibility = 'hidden';
    tip.style.position   = 'absolute';
    tip.style.zIndex     = '9999';
    document.body.appendChild(tip);

    const tw = tip.offsetWidth;
    const th = tip.offsetHeight;

    const GAP = 8;
    let top = 0, left = 0;

    switch (pos) {
      case 'top':
        top  = rect.top + scrollY - th - GAP;
        left = rect.left + scrollX + (rect.width - tw) / 2;
        break;
      case 'bottom':
        top  = rect.bottom + scrollY + GAP;
        left = rect.left + scrollX + (rect.width - tw) / 2;
        break;
      case 'left':
        top  = rect.top + scrollY + (rect.height - th) / 2;
        left = rect.left + scrollX - tw - GAP;
        break;
      case 'right':
        top  = rect.top + scrollY + (rect.height - th) / 2;
        left = rect.right + scrollX + GAP;
        break;
    }

    tip.style.top  = `${top}px`;
    tip.style.left = `${left}px`;
    tip.style.visibility = 'visible';
  }
}

