@keyframes bounce-in {
  from { transform: scale(0.5); opacity: 0; }
  to   { transform: scale(1);   opacity: 1; }
}

@media (max-width: 480px) {
  .error-code { font-size: 5rem; }
  .error-icon { font-size: 3.5rem; }
}

