      line-height: 1.6;
      color: var(--text-color-secondary);
    }

    .footer__column-title {
      margin: 0 0 var(--space-4);
      font-size: var(--text-sm);
      font-weight: 600;
      color: var(--text-color);
      text-transform: uppercase;
      letter-spacing: 0.05em;
    }

    .footer__column-links {
      display: flex;
      flex-direction: column;
