  to { transform: translateY(0); opacity: 1; }
}

@keyframes modalSlideDown {
  from { transform: translateY(0); opacity: 1; }
  to { transform: translateY(20px); opacity: 0; }
}

/* Sizes */
.modal-sm { max-width: 400px; }
.modal-md { max-width: 550px; }
