  selector: 'app-popup-container',
  standalone: true,
  imports: [],
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    @for (popup of popupService.popups(); track popup.id) {
      <div 
        class="popup-overlay" 
        [class.popup-closing]="popup.closing"
