:host {
  display: block;
  width: 100%;
}

.select2-wrapper {
  position: relative;
  width: 100%;
  min-width: 15rem;
}

.select2-wrapper.disabled {
  opacity: 0.6;
  pointer-events: none;
}

.select2-wrapper.has-label {
  margin-top: var(--space-3);
}

/* === TRIGGER === */
.select2-trigger {
  position: relative;
  display: flex;
  align-items: center;
  height: var(--control-height);
  padding: var(--space-1) var(--space-3);
  padding-right: 2.75rem;
  background: var(--input-bg);
  border: var(--input-border-width, 1.5px) solid var(--input-border);
  border-radius: var(--radius-md);
  cursor: pointer;
  transition: all 200ms ease;
  font-size: var(--text-sm);
  box-sizing: border-box;
  box-shadow: var(--input-shadow);
}

.select2-wrapper.has-label .select2-trigger {
  padding: var(--space-1) var(--space-3);
}

/* === FLOATING LABEL === */
.floating-label {
  position: absolute;
  left: var(--space-3);
  top: 50%;
  transform: translateY(-50%);
  font-size: var(--text-sm);
  color: var(--input-placeholder);
  pointer-events: none;
  transition: all 200ms cubic-bezier(0.4, 0, 0.2, 1);
  background: var(--input-bg);
  padding: 0 var(--space-2);
  white-space: nowrap;
}

.select2-wrapper.focused .floating-label,
.select2-wrapper.has-value .floating-label {
  top: -0.625rem;
  transform: translateY(0);
  font-size: var(--text-xs);
  font-weight: 500;
  color: var(--primary-color);
}

/* === MULTI-SELECT FIX === */
.select2-wrapper.multiple .select2-trigger {
  min-height: var(--control-height);
  height: auto;
  padding: var(--space-1) var(--space-3);
  padding-right: 2.75rem;
  align-items: center;
}

.select2-wrapper.focused .select2-trigger,
.select2-trigger:hover {
  border-color: var(--input-border-focus);
}

.select2-wrapper.focused .select2-trigger {
  box-shadow: var(--shadow-focus-primary);
}

.select2-value {
  display: flex;
  align-items: center;
  gap: var(--space-2);
  flex: 1;
  font-size: var(--text-sm);
  color: var(--input-text);
  line-height: normal;
}

.placeholder {
  color: var(--input-placeholder);
}

.select2-arrow {
  position: absolute;
  right: var(--space-3);
  top: 50%;
  transform: translateY(-50%);
  color: var(--text-color-secondary);
  transition: transform 200ms ease;
}

.select2-wrapper.open .select2-arrow {
  transform: translateY(-50%) rotate(180deg);
}

/* === TAGS (Multiple) === */
.select2-tags {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-1);
  flex: 1;
  padding: var(--space-1) 0;
}

.select2-tag {
  display: inline-flex;
  align-items: center;
  gap: var(--space-1);
  padding: var(--space-1) var(--space-2);
  background: var(--primary-color-lighter);
  color: var(--primary-color);
  border-radius: var(--radius-full);
  font-size: var(--text-xs);
  font-weight: 500;
}

.tag-remove {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 1rem;
  height: 1rem;
  padding: 0;
  background: none;
  border: none;
  border-radius: 50%;
  font-size: var(--text-sm);
  color: var(--primary-color);
  cursor: pointer;
  transition: all 150ms ease;
}

.tag-remove:hover {
  background: var(--primary-color-lighter);
}

/* === DROPDOWN === */
.select2-dropdown {
  position: absolute;
  top: calc(100% + 4px);
  left: 0;
  right: 0;
  background: var(--dropdown-bg);
  border: 1px solid var(--dropdown-border);
  border-radius: var(--radius-md);
  box-shadow: var(--shadow-dropdown);
  z-index: 10000;
  animation: dropdownSlide 200ms ease;
  overflow: hidden;
}

@keyframes dropdownSlide {
  from { opacity: 0; transform: translateY(-8px); }
  to { opacity: 1; transform: translateY(0); }
}

/* === SEARCH === */
.select2-search {
  position: relative;
  padding: var(--space-2);
  border-bottom: 1px solid var(--dropdown-border);
}

.search-input {
  width: 100%;
  padding: var(--space-2) var(--space-3);
  padding-left: 2.25rem;
  font-size: var(--text-md);
  border: 1px solid var(--input-border);
  border-radius: var(--radius-sm);
  background: var(--input-bg);
  color: var(--input-text);
  outline: none;
  transition: all 150ms ease;
}

.search-input:focus {
  border-color: var(--primary-color);
  background: var(--input-bg);
}

.search-icon {
  position: absolute;
  left: var(--space-4);
  top: 50%;
  transform: translateY(-50%);
  font-size: var(--text-sm);
}

/* === OPTIONS === */
.select2-options {
  max-height: 240px;
  overflow-y: auto;
}

.select2-option {
  display: flex;
  align-items: center;
  gap: var(--space-2);
  padding: var(--space-3) var(--space-4);
  font-size: var(--text-md);
  color: var(--dropdown-text, var(--text-color));
  cursor: pointer;
  transition: background 100ms ease;
}

.select2-option:hover:not(.disabled),
.select2-option.highlighted:not(.disabled) {
  background: var(--dropdown-item-hover);
}

.select2-option.selected {
  background: var(--dropdown-item-selected);
  color: var(--primary-color);
  font-weight: 500;
}

.select2-option.disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.option-icon {
  font-size: var(--text-md);
}

.option-label {
  flex: 1;
}

.check-icon {
  color: var(--primary-color);
  font-weight: bold;
}

.select2-no-results {
  padding: var(--space-4);
  text-align: center;
  color: var(--text-color-muted);
  font-size: var(--text-sm);
}

/* Dark mode handled automatically by CSS variables */

