(
    req: HttpRequest<unknown>,
    next: HttpHandlerFn
): Observable<HttpEvent<unknown>> => {
    const tokenService = inject(TokenService);
    const authService = inject(AuthService);

    // Skip public URLs
    if (isPublicUrl(req.url)) {
        return next(req);
    }

    // Get current token
    const token = tokenService.getTokenApp(DEFAULT_APP_ID);

    // Add token if available
    if (token) {
        req = addTokenHeader(req, token);
    }

    return next(req).pipe(
        catchError((error: HttpErrorResponse) => {
            // Handle 401 Unauthorized
            if (error.status === 401 && token) {
                return handle401Error(req, next, tokenService, authService);
            }

            return throwError(() => error);
        })
    );
}

(
  req: HttpRequest<unknown>,
  next: HttpHandlerFn
): Observable<HttpEvent<unknown>> => {
  if (req.method !== 'GET') {
    return next(req);
  }

  if (req.headers.has('X-No-Cache')) {
    const cleanReq = req.clone({ headers: req.headers.delete('X-No-Cache') });
    return next(cleanReq);
  }

  const ttl = req.headers.has('X-Cache-TTL')
    ? Number.parseInt(req.headers.get('X-Cache-TTL') ?? '', 10)
    : DEFAULT_TTL;

  const cacheKey = req.urlWithParams;
  const cached = cache.get(cacheKey);

  if (cached && Date.now() - cached.timestamp < ttl) {
    return of(cached.response.clone());
  }

  return next(req).pipe(
    tap(event => {
      if (event instanceof HttpResponse && event.status === 200) {
        cache.set(cacheKey, { response: event.clone(), timestamp: Date.now() });
        cleanExpiredCache(ttl);
      }
    })
  );
}

